import { useLocation, Link, useSearchParams } from "react-router-dom";
import {
    Users, UsersRound, Building2, FileText, MapPinned,
    Heart, CalendarDays, Handshake, Crown, LayoutDashboard,
    ArrowUpDown, FolderOpen, Lock, Bell, AlertCircle, TrendingUp,
    ChevronRight, ArrowRight, User, Settings, ShieldCheck, History, HardDrive, Layers,
    Sparkles, HelpCircle
} from "lucide-react";
import { useChurch } from "@/contexts/ChurchContext";
import { Badge } from "@/components/ui/badge";
import { MordusLogo } from "@/components/MordusLogo";
import { useMemo } from "react";
import {
    Sidebar,
    SidebarContent,
    SidebarHeader,
    SidebarGroup,
    SidebarGroupContent,
    SidebarGroupLabel,
    SidebarMenu,
    SidebarMenuItem,
    SidebarMenuButton,
    SidebarFooter,
    useSidebar
} from "@/components/ui/sidebar";
import { CopilotSidebarAlert } from "@/components/Copilot/CopilotSidebarAlert";

interface SubItem {
    title: string;
    url: string;
    icon: any;
    badge?: string;
}

const GERAL_ITEMS: SubItem[] = [
    { title: "Painel Tesouraria", url: "/", icon: LayoutDashboard },
    { title: "Painel Secretaria", url: "/?view=secretaria", icon: UsersRound },
];

const SECRETARIA_ITEMS: SubItem[] = [
    { title: "Membros", url: "/membros?tab=membros", icon: Users },
    { title: "Lideran├ºa", url: "/membros?tab=lideranca", icon: Crown },
    { title: "Departamentos", url: "/membros?tab=departamentos", icon: Layers },
    { title: "Patrim├┤nio", url: "/membros?tab=patrimonio", icon: Building2 },
    { title: "Documentos", url: "/membros?tab=documentos", icon: FileText },
    { title: "Congrega├º├Áes", url: "/membros?tab=congregacoes", icon: MapPinned },
    { title: "Calend├írio", url: "/membros?tab=calendario", icon: CalendarDays },
    { title: "A├º├úo Social", url: "/membros?tab=social", icon: Heart },
    { title: "Parcerias", url: "/membros?tab=parceiros", icon: Handshake },
];

const TESOURARIA_ITEMS: SubItem[] = [
    { title: "Lan├ºamentos", url: "/lancamentos?tab=movimentacoes", icon: ArrowUpDown },
    { title: "Categorias", url: "/lancamentos?tab=categorias", icon: FolderOpen },
    { title: "Fechamento", url: "/lancamentos?tab=fechamento", icon: Lock, badge: "Novo" },
    { title: "Relat├│rios", url: "/lancamentos?tab=relatorios", icon: FileText },
];

const SISTEMA_ITEMS: SubItem[] = [
    { title: "Meu Perfil", url: "/configuracoes?tab=perfil", icon: User },
    { title: "Institui├º├úo", url: "/configuracoes?tab=igreja", icon: Building2 },
    { title: "Financeiro", url: "/configuracoes?tab=financeiro", icon: ArrowUpDown },
    { title: "Armazenamento", url: "/configuracoes?tab=armazenamento", icon: HardDrive },
    { title: "Digital", url: "/configuracoes?tab=digital", icon: FileText },
    { title: "Configura├º├Áes", url: "/configuracoes?tab=preferencias", icon: Settings },
    { title: "Equipe", url: "/configuracoes?tab=equipe", icon: ShieldCheck },
    { title: "Auditoria", url: "/configuracoes?tab=auditoria", icon: History },
    { title: "Avan├ºado", url: "/configuracoes?tab=avancado", icon: Lock },
];

const HELP_INDEX_ITEMS = [
    { title: "Hist├│ria e Valores", id: "fundamentos", icon: Sparkles },
    { title: "M├│dulos do Sistema", id: "manual-completo", icon: Layers },
    { title: "Tutoriais Cr├¡ticos", id: "tutoriais", icon: History },
    { title: "D├║vidas Frequentes", id: "faq", icon: HelpCircle },
];

export function ContextSidebar() {
    const location = useLocation();
    const [searchParams] = useSearchParams();
    const { settings, user, logout, isAdmin, canManageFinances, canManageSecretariat, canAccessSecretariat } = useChurch();
    const path = location.pathname;
    const { state } = useSidebar();
    const isCollapsed = state === "collapsed";

    const filteredGeralItems = useMemo(() => {
        return GERAL_ITEMS.filter(item => {
            if (item.url === "/?view=secretaria") return canAccessSecretariat;
            return true;
        });
    }, [canAccessSecretariat]);

    const context = useMemo(() => {
        if (path === "/") return "geral";
        if (path.startsWith("/configuracoes") || path.startsWith("/ajuda")) return "sistema";
        if (path.startsWith("/membros") ||
            path.startsWith("/secretaria") ||
            path.startsWith("/patrimonio") ||
            path.startsWith("/documentos") ||
            path.startsWith("/congregacoes") ||
            path.startsWith("/departamentos") ||
            path.startsWith("/servico-social") ||
            path.startsWith("/calendario") ||
            path.startsWith("/parceiros") ||
            path.startsWith("/lideranca")) {
            return "secretaria";
        }
        return "tesouraria";
    }, [path]);

    const isItemActive = useMemo(() => {
        const fullPath = location.pathname + location.search;
        return (url: string) => {
            const [urlPath, urlSearch] = url.split("?");

            // Dashboard case (Geral context)
            if (urlPath === "/" && path === "/") {
                const currentView = searchParams.get("view") || "tesouraria";
                const targetView = urlSearch ? new URLSearchParams(urlSearch).get("view") : "tesouraria";
                return currentView === targetView;
            }

            // Dashboard case inside member module
            if (url === "/membros?tab=resumo") {
                return location.pathname === "/membros" && (!location.search || location.search.includes("tab=resumo"));
            }
            // Settings profile case (default tab is perfil)
            if (url === "/configuracoes?tab=perfil") {
                return location.pathname === "/configuracoes" && (!location.search || location.search.includes("tab=perfil"));
            }
            // Transactions default case
            if (url === "/lancamentos?tab=movimentacoes") {
                return location.pathname === "/lancamentos" && (!location.search || location.search.includes("tab=movimentacoes"));
            }
            // Other tab cases
            if (url.includes("?tab=")) {
                return fullPath === url;
            }
            // General case
            return location.pathname === url;
        };
    }, [location, searchParams, path]);

    const items = context === "geral" ? filteredGeralItems : context === "secretaria" ? SECRETARIA_ITEMS : context === "tesouraria" ? TESOURARIA_ITEMS : context === "sistema" ? SISTEMA_ITEMS : [];
    const title = context === "geral" ? "" : context === "secretaria" ? "Secretaria" : context === "tesouraria" ? "Tesouraria" : "Sistema";

    // Special logic for Help page - Index in Sidebar
    if (path === "/ajuda") {
        return (
            <div className={`border-r border-sidebar-border bg-sidebar-context flex flex-col h-screen transition-all duration-300 ease-in-out overflow-hidden ${isCollapsed ? "w-0 opacity-0" : "w-64 opacity-100"}`}>
                <div className="w-64 flex flex-col h-full">
                    <div className="p-6 pb-2">
                        <MordusLogo variant="full" className="h-5 w-auto mb-6" />
                        <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground/70 mb-4">Central de Ajuda</h2>
                    </div>

                    <div className="flex-1 px-3 overflow-y-auto no-scrollbar">
                        <div className="space-y-1 py-2">
                            {HELP_INDEX_ITEMS.map((item) => (
                                <a
                                    key={item.id}
                                    href={`#${item.id}`}
                                    className="flex items-center gap-3 px-3 py-2.5 rounded-xl text-muted-foreground hover:bg-secondary/50 hover:text-foreground transition-all text-sm font-medium group"
                                >
                                    <item.icon className="h-4 w-4 opacity-50 group-hover:opacity-100 transition-opacity" />
                                    <span className="text-[13px]">{item.title}</span>
                                </a>
                            ))}
                        </div>
                    </div>

                    <div className="p-4 mt-auto space-y-3">
                        <div className="px-3">
                            <div className="h-px w-full bg-border/50 mb-4" />
                            <Link to="/" className="flex items-center gap-3 py-2 rounded-xl text-muted-foreground hover:text-foreground transition-all text-[11px] font-black uppercase tracking-widest group">
                                <ArrowRight className="h-3 w-3 rotate-180 group-hover:-translate-x-1 transition-transform" /> Voltar ao In├¡cio
                            </Link>
                        </div>

                        <div className="bg-orange-500/10 dark:bg-orange-500/20 border border-orange-500/20 rounded-2xl p-4">
                            <div className="flex items-center gap-2 mb-2">
                                <div className="h-2 w-2 rounded-full bg-orange-500 animate-pulse" />
                                <span className="text-[9px] font-black uppercase tracking-widest text-[#1A1A1A] dark:text-white">Leitura M├│vel</span>
                            </div>
                            <p className="text-[10px] font-medium text-muted-foreground leading-relaxed">
                                Use o ├¡ndice para saltar entre os t├│picos essenciais.
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className={`border-r border-sidebar-border bg-sidebar-context flex flex-col h-screen sticky top-0 transition-all duration-300 ease-in-out overflow-hidden ${isCollapsed ? "w-0 opacity-0" : "w-64 opacity-100"}`}>
            <div className="w-64 flex flex-col h-full">
                <div className="p-6 pb-2">
                    <div className="mb-4">
                        <MordusLogo variant="full" className="h-5 w-auto" />
                    </div>
                    {title && (
                        <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground/70 mb-4 animate-in fade-in slide-in-from-left-2 duration-300">
                            {title}
                        </h2>
                    )}
                </div>

                <div className="flex-1 px-3 overflow-y-auto no-scrollbar">
                    <div className="space-y-1 py-2">
                        {items.map((item) => {
                            const active = isItemActive(item.url);
                            return (
                                <Link
                                    key={item.url}
                                    to={item.url}
                                    className={`flex items-center justify-between px-3 py-2 rounded-xl transition-all group ${active
                                        ? "bg-primary/10 text-primary"
                                        : "text-muted-foreground hover:bg-secondary/50 hover:text-foreground"
                                        }`}
                                >
                                    <div className="flex items-center gap-3">
                                        <item.icon className={`h-4 w-4 transition-transform group-hover:scale-110 ${active ? "text-primary" : "text-muted-foreground/60"}`} />
                                        <span className={`text-[13px] ${active ? "font-bold" : "font-medium"}`}>{item.title}</span>
                                    </div>
                                    {item.badge ? (
                                        <Badge variant="secondary" className="bg-primary/10 text-primary text-[8px] font-black uppercase px-1.5 py-0 h-4 border-primary/20">
                                            {item.badge}
                                        </Badge>
                                    ) : (
                                        active && <ChevronRight className="h-3 w-3 opacity-50" />
                                    )}
                                </Link>
                            );
                        })}
                    </div>
                </div>

                <div className="px-4 pb-4 mt-auto space-y-3">
                    <CopilotSidebarAlert />

                    <div className="bg-secondary/20 border border-border/50 rounded-2xl p-4 relative overflow-hidden group">
                        <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-20 transition-opacity">
                            <TrendingUp className="h-12 w-12 text-primary" />
                        </div>
                        <div className="flex items-center gap-2 mb-2">
                            <div className="h-2 w-2 rounded-full bg-success animate-pulse" />
                            <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Status do Dia</span>
                        </div>
                        <p className="text-[11px] font-medium text-foreground leading-tight">
                            {context === 'secretaria' ? 'N├úo h├í aniversariantes hoje.' : 'Todas as contas est├úo em dia.'}
                        </p>
                        <Link to="/ajuda" className="flex items-center gap-1 text-[10px] text-primary font-bold mt-3 hover:gap-2 transition-all">
                            VER DETALHES <ArrowRight className="h-3 w-3" />
                        </Link>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from "react";
import { Sparkles, Loader2 } from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/lib/supabase";
import { useChurch } from "@/contexts/ChurchContext";

interface AIInsightCardProps {
    mode?: "tesouraria" | "secretaria";
}

export function AIInsightCard({ mode = "tesouraria" }: AIInsightCardProps) {
    const { organization, profile } = useChurch();
    const [currentIndex, setCurrentIndex] = useState(0);

    const { data: insight, isLoading, isError, refetch } = useQuery({
        queryKey: ["dashboard-ai-insight", organization?.id, mode],
        queryFn: async () => {
            if (!organization?.id) return null;

            const { data, error } = await supabase.functions.invoke("mordus-copilot", {
                body: {
                    message: `Gere um resumo estrat├®gico focado em ${mode} em exatas 3 frases cursas. Use dados reais. Proibido usar n├║meros, t├│picos ou prefixos.`,
                    context: {
                        user_role: profile?.role,
                        organization_name: organization?.name,
                        organization_id: organization?.id,
                        current_page: "/dashboard",
                        dashboard_mode: mode
                    }
                }
            });

            if (error) throw error;
            return data?.reply;
        },
        enabled: !!organization?.id,
        staleTime: 1000 * 60 * 30, // 30 minutes
    });

    // Limpeza profunda das frases para remover lixo de formata├º├úo da IA
    const sentences = insight
        ? insight
            .split(/[.!?]/)
            .map((s: string) => s.replace(/^\d+[\s.)|-]+/, "").trim()) // Limpa "1. ", "01 - ", etc.
            .filter((s: string) => s.length > 5)
        : [];

    useEffect(() => {
        if (sentences.length <= 1) return;

        const interval = setInterval(() => {
            setCurrentIndex((prev) => (prev + 1) % sentences.length);
        }, 6000);

        return () => clearInterval(interval);
    }, [sentences]);

    if (!organization) return null;

    return (
        <Card className="bg-gradient-to-br from-card to-secondary/30 border-primary/20 shadow-sm overflow-hidden group">
            <CardContent className="p-4 sm:p-5">
                <div className="flex items-center gap-4">
                    <div className="h-10 w-10 shrink-0 rounded-xl bg-primary/10 flex items-center justify-center group-hover:rotate-12 transition-transform duration-300">
                        <Sparkles className="h-5 w-5 text-primary" />
                    </div>

                    <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between mb-1">
                            <div className="flex items-center gap-2">
                                <h3 className="text-[11px] font-black uppercase tracking-widest text-primary/80">Intelig├¬ncia Mordus</h3>
                                <span className="flex h-1.5 w-1.5 rounded-full bg-primary/50 animate-pulse" />
                            </div>
                            <button
                                onClick={() => {
                                    refetch();
                                    setCurrentIndex(0);
                                }}
                                className="text-[10px] text-muted-foreground hover:text-primary transition-colors flex items-center gap-1"
                            >
                                {isLoading ? <Loader2 className="h-3 w-3 animate-spin" /> : "Atualizar"}
                            </button>
                        </div>

                        <div className="h-10 flex items-center">
                            {isLoading ? (
                                <div className="h-4 w-full bg-secondary/50 animate-pulse rounded" />
                            ) : isError ? (
                                <p className="text-[13px] text-muted-foreground">Ocorreu um erro ao carregar insights.</p>
                            ) : sentences.length > 0 ? (
                                <div className="relative w-full h-full flex items-center overflow-hidden">
                                    {sentences.map((stmt: string, i: number) => (
                                        <p
                                            key={i}
                                            className={`text-[14px] font-medium text-foreground leading-tight absolute transition-all duration-700 ease-in-out ${i === currentIndex
                                                ? "opacity-100 translate-y-0"
                                                : "opacity-0 translate-y-4 pointer-events-none"
                                                }`}
                                        >
                                            {stmt}.
                                        </p>
                                    ))}
                                </div>
                            ) : (
                                <p className="text-[14px] font-medium text-foreground opacity-60 italic">
                                    {insight || "Aguardando novos dados para gerar insights estrat├®gicos."}
                                </p>
                            )}
                        </div>
                    </div>
                </div>
            </CardContent>
        </Card>
    );
}

import { useState, useEffect, useCallback } from "react";
import {
    Search,
    Users,
    Building2,
    ArrowUpDown,
    Command as CommandIcon,
    Loader2,
    CalendarDays,
    FileText,
    LayoutDashboard,
    UsersRound,
    Settings
} from "lucide-react";
import {
    CommandDialog,
    CommandEmpty,
    CommandGroup,
    CommandInput,
    CommandItem,
    CommandList,
    CommandSeparator,
} from "@/components/ui/command";
import { useNavigate } from "react-router-dom";
import { supabase } from "@/lib/supabase";
import { useChurch } from "@/contexts/ChurchContext";

interface SearchResult {
    id: string;
    title: string;
    subtitle?: string;
    type: "member" | "department" | "transaction" | "page";
    url: string;
    icon: any;
}

export function GlobalSearch() {
    const [open, setOpen] = useState(false);
    const [query, setQuery] = useState("");
    const [results, setResults] = useState<SearchResult[]>([]);
    const [loading, setLoading] = useState(false);
    const { organization } = useChurch();
    const navigate = useNavigate();

    // Pages to include in search
    const pages: SearchResult[] = [
        { id: "p-dashboard", title: "Painel Geral", type: "page", url: "/", icon: LayoutDashboard },
        { id: "p-lancamentos", title: "Financeiro (Lan├ºamentos)", type: "page", url: "/lancamentos", icon: ArrowUpDown },
        { id: "p-membros", title: "Membros (Secretaria)", type: "page", url: "/membros", icon: Users },
        { id: "p-departamentos", title: "Departamentos", type: "page", url: "/departamentos", icon: UsersRound },
        { id: "p-relatorios", title: "Relat├│rios", type: "page", url: "/relatorios", icon: FileText },
        { id: "p-patrimonio", title: "Patrim├┤nio", type: "page", url: "/patrimonio", icon: Building2 },
        { id: "p-configuracoes", title: "Configura├º├Áes", type: "page", url: "/configuracoes", icon: Settings },
    ];

    useEffect(() => {
        const down = (e: KeyboardEvent) => {
            if (e.key === "k" && (e.metaKey || e.ctrlKey)) {
                e.preventDefault();
                setOpen((open) => !open);
            }
        };

        document.addEventListener("keydown", down);
        return () => document.removeEventListener("keydown", down);
    }, []);

    const performSearch = useCallback(async (searchTerm: string) => {
        if (!searchTerm || searchTerm.length < 2 || !organization?.id) {
            setResults([]);
            return;
        }

        setLoading(true);
        try {
            const [{ data: members }, { data: depts }, { data: txs }] = await Promise.all([
                supabase
                    .from("members")
                    .select("id, full_name, phone")
                    .eq("organization_id", organization.id)
                    .ilike("full_name", `%${searchTerm}%`)
                    .limit(5),
                supabase
                    .from("departments")
                    .select("id, name")
                    .eq("organization_id", organization.id)
                    .ilike("name", `%${searchTerm}%`)
                    .limit(5),
                supabase
                    .from("transactions")
                    .select("id, description, amount, type")
                    .eq("organization_id", organization.id)
                    .ilike("description", `%${searchTerm}%`)
                    .limit(5),
            ]);

            const formattedResults: SearchResult[] = [];

            members?.forEach((m) => {
                formattedResults.push({
                    id: m.id,
                    title: m.full_name,
                    subtitle: m.phone || "Sem telefone",
                    type: "member",
                    url: `/membros`,
                    icon: Users,
                });
            });

            depts?.forEach((d) => {
                formattedResults.push({
                    id: d.id,
                    title: d.name,
                    type: "department",
                    url: `/departamentos`,
                    icon: Building2,
                });
            });

            txs?.forEach((t) => {
                formattedResults.push({
                    id: t.id,
                    title: t.description,
                    subtitle: `${t.type === "income" ? "+" : "-"} R$ ${t.amount.toLocaleString("pt-BR")}`,
                    type: "transaction",
                    url: "/lancamentos",
                    icon: ArrowUpDown,
                });
            });

            setResults(formattedResults);
        } catch (err) {
            console.error("Search error:", err);
        } finally {
            setLoading(false);
        }
    }, [organization?.id]);

    useEffect(() => {
        const timer = setTimeout(() => {
            performSearch(query);
        }, 300);

        return () => clearTimeout(timer);
    }, [query, performSearch]);

    const onSelect = (url: string) => {
        setOpen(false);
        setQuery("");
        navigate(url);
    };

    const filteredPages = pages.filter(p =>
        p.title.toLowerCase().includes(query.toLowerCase())
    );

    return (
        <>
            <div
                onClick={() => setOpen(true)}
                className="flex-1 max-w-sm relative group mx-4 h-8 flex items-center cursor-pointer"
            >
                <Search className="absolute left-2.5 h-3.5 w-3.5 text-muted-foreground group-hover:text-primary transition-colors" />
                <div className="w-full h-8 bg-secondary/50 border border-border/50 pl-8 pr-3 flex items-center text-[13px] text-muted-foreground hover:bg-secondary/70 transition-all rounded-lg">
                    <span>Pesquisar no Mordus...</span>
                    <div className="ml-auto flex items-center gap-1 opacity-50">
                        <CommandIcon className="h-2.5 w-2.5" />
                        <span className="text-[10px]">K</span>
                    </div>
                </div>
            </div>

            <CommandDialog open={open} onOpenChange={setOpen}>
                <CommandInput
                    placeholder="O que voc├¬ est├í procurando?"
                    value={query}
                    onValueChange={setQuery}
                />
                <CommandList>
                    <CommandEmpty>
                        {loading ? (
                            <div className="flex items-center justify-center p-4">
                                <Loader2 className="h-4 w-4 animate-spin mr-2" />
                                <span>Pesquisando...</span>
                            </div>
                        ) : (
                            "Nenhum resultado encontrado."
                        )}
                    </CommandEmpty>

                    {filteredPages.length > 0 && (
                        <CommandGroup heading="P├íginas e Navega├º├úo">
                            {filteredPages.map((item) => (
                                <CommandItem key={item.id} onSelect={() => onSelect(item.url)}>
                                    <item.icon className="mr-2 h-4 w-4 text-primary" />
                                    <span>{item.title}</span>
                                </CommandItem>
                            ))}
                        </CommandGroup>
                    )}

                    {results.length > 0 && (
                        <>
                            <CommandSeparator />
                            <CommandGroup heading="Resultados da Busca">
                                {results.map((item) => (
                                    <CommandItem key={item.id} onSelect={() => onSelect(item.url)}>
                                        <item.icon className="mr-2 h-4 w-4 text-muted-foreground" />
                                        <div className="flex flex-col">
                                            <span>{item.title}</span>
                                            {item.subtitle && <span className="text-[10px] text-muted-foreground">{item.subtitle}</span>}
                                        </div>
                                        <span className="ml-auto text-[10px] uppercase text-muted-foreground/50 font-bold tracking-tighter">
                                            {item.type === "member" ? "Membro" : item.type === "department" ? "Depto" : "Financeiro"}
                                        </span>
                                    </CommandItem>
                                ))}
                            </CommandGroup>
                        </>
                    )}
                </CommandList>
            </CommandDialog>
        </>
    );
}

import { useState, useEffect } from "react";
import { useGoogleDrive } from "@/hooks/useGoogleDrive";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Folder, HardDrive, RefreshCw, Plus, Check, ExternalLink, FileIcon } from "lucide-react";
import { toast } from "sonner";
import { GoogleDriveFolder } from "@/lib/googleDrive";

export function GoogleDriveConnector() {
    const { service, isConnected, connect, saveRootFolder, currentFolderId, isLoading } = useGoogleDrive();
    const [folders, setFolders] = useState<GoogleDriveFolder[]>([]);
    const [contents, setContents] = useState<GoogleDriveFolder[]>([]);
    const [newFolderName, setNewFolderName] = useState("");
    const [isListing, setIsListing] = useState(false);
    const [isListingContents, setIsListingContents] = useState(false);
    const [currentFolderName, setCurrentFolderName] = useState<string | null>(null);
    const [path, setPath] = useState<{ id: string, name: string }[]>([]);

    useEffect(() => {
        if (service && isConnected) {
            loadFolders();
            if (currentFolderId) {
                service.getFolder(currentFolderId).then(f => {
                    if (f) {
                        setCurrentFolderName(f.name);
                        setPath([{ id: f.id, name: f.name }]);
                        loadContents(f.id);
                    }
                });
            }
        }
    }, [service, isConnected, currentFolderId]);

    const loadFolders = async () => {
        if (!service) return;
        setIsListing(true);
        try {
            const list = await service.listFolders();
            setFolders(list);
        } catch (error) {
            console.error(error);
        } finally {
            setIsListing(false);
        }
    };

    const loadContents = async (folderId: string) => {
        if (!service) return;
        setIsListingContents(true);
        try {
            // @ts-expect-error - Usando fetchGoogleApi interno para chamadas customizadas
            const list = await service.fetchGoogleApi(`/files?q='${folderId}' in parents and trashed = false&fields=files(id,name,mimeType)`);
            setContents(list.files || []);
        } catch (error) {
            console.error(error);
            toast.error("Erro ao carregar conte├║do");
        } finally {
            setIsListingContents(false);
        }
    };

    const navigateTo = (folder: { id: string, name: string }, isBack: boolean = false) => {
        if (isBack) {
            const index = path.findIndex(p => p.id === folder.id);
            const newPath = path.slice(0, index + 1);
            setPath(newPath);
        } else {
            setPath([...path, folder]);
        }
        loadContents(folder.id);
    };

    const handleCreateRootFolder = async () => {
        if (!service || !newFolderName) return;
        try {
            const folder = await service.createFolder(newFolderName);
            toast.success(`Pasta "${newFolderName}" criada!`);
            await saveRootFolder(folder.id);
            setNewFolderName("");
            loadFolders();
        } catch (error) {
            toast.error("Erro ao criar pasta");
        }
    };

    const handleCreateSubfolder = async () => {
        const activeFolderId = path[path.length - 1]?.id || currentFolderId;
        if (!service || !newFolderName || !activeFolderId) return;
        try {
            await service.createFolder(newFolderName, activeFolderId);
            toast.success(`Subpasta "${newFolderName}" criada!`);
            setNewFolderName("");
            loadContents(activeFolderId);
        } catch (error) {
            toast.error("Erro ao criar subpasta");
        }
    };

    if (isLoading) return (
        <div className="flex items-center justify-center p-12">
            <RefreshCw className="h-8 w-8 animate-spin text-primary opacity-20" />
        </div>
    );

    if (!isConnected) {
        return (
            <Card className="bg-card border-border shadow-sm">
                <CardHeader>
                    <CardTitle className="flex items-center gap-2 text-lg">
                        <HardDrive className="h-5 w-5 text-primary" />
                        Conectar Armazenamento Cloud
                    </CardTitle>
                    <CardDescription>
                        Integre o Google Drive para gerenciar todos os documentos da organiza├º├úo em um s├│ lugar.
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <Button onClick={connect} className="gap-2 h-11 px-8 rounded-xl font-bold shadow-lg shadow-primary/20 transition-all hover:scale-105 active:scale-95">
                        <img src="https://www.google.com/favicon.ico" className="w-4 h-4" alt="Google" />
                        Conectar com Google Drive
                    </Button>
                </CardContent>
            </Card>
        );
    }

    const activeFolder = path[path.length - 1];

    return (
        <div className="space-y-6">
            <Card className="bg-card border-border shadow-sm overflow-hidden">
                <CardHeader className="pb-4 bg-secondary/10">
                    <div className="flex items-center justify-between">
                        <div>
                            <CardTitle className="flex items-center gap-2 text-md">
                                <Check className="h-4 w-4 text-success" />
                                Google Drive Conectado
                            </CardTitle>
                            <CardDescription className="text-xs">
                                Sua conta do Google est├í vinculada e pronta para uso.
                            </CardDescription>
                        </div>
                        {currentFolderName && (
                            <Button variant="outline" size="sm" className="h-8 text-[10px] font-black uppercase tracking-widest text-destructive hover:bg-destructive/10 border-destructive/20" onClick={() => setCurrentFolderName(null)}>Desvincular</Button>
                        )}
                    </div>
                </CardHeader>
                <CardContent className="pt-6">
                    {!currentFolderName && (
                        <div className="space-y-4">
                            <div className="flex gap-2">
                                <Input
                                    placeholder="Nome da nova pasta raiz..."
                                    className="h-10 text-sm bg-background/50 border-input"
                                    value={newFolderName}
                                    onChange={(e) => setNewFolderName(e.target.value)}
                                />
                                <Button onClick={handleCreateRootFolder} variant="secondary" className="gap-2 shrink-0 h-10 px-6 font-bold rounded-xl border border-border shadow-sm">
                                    <Plus className="h-4 w-4" /> Criar Pasta Raiz
                                </Button>
                            </div>

                            <div className="border border-border/50 rounded-2xl overflow-hidden bg-background/30 backdrop-blur-sm">
                                <div className="p-3 border-b border-border/50 bg-secondary/20 flex justify-between items-center sticky top-0 z-10">
                                    <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground/80 pl-2">Selecionar Pasta Existente</span>
                                    <Button variant="ghost" size="icon" className="h-7 w-7 hover:bg-background/80" onClick={loadFolders} disabled={isListing}>
                                        <RefreshCw className={`h-3.5 w-3.5 text-muted-foreground ${isListing ? 'animate-spin text-primary' : ''}`} />
                                    </Button>
                                </div>
                                <div className="max-h-[250px] overflow-y-auto divide-y divide-border/30">
                                    {folders.length === 0 && !isListing && (
                                        <div className="p-10 text-center text-xs text-muted-foreground/60 italic font-medium">
                                            Nenhuma pasta encontrada no seu Drive.
                                        </div>
                                    )}
                                    {folders.map((folder) => (
                                        <div
                                            key={folder.id}
                                            className="p-4 hover:bg-primary/5 cursor-pointer flex items-center justify-between transition-all group"
                                            onClick={() => saveRootFolder(folder.id)}
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className="h-8 w-8 rounded-lg bg-blue-500/10 flex items-center justify-center border border-blue-500/10 group-hover:bg-blue-500/20 transition-all">
                                                    <Folder className="h-4 w-4 text-blue-500 fill-blue-500/20" />
                                                </div>
                                                <span className="text-sm font-semibold text-foreground/80 tracking-tight">{folder.name}</span>
                                            </div>
                                            <div className="h-6 w-6 rounded-full border border-border flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                                <Plus className="h-3 w-3 text-muted-foreground" />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}

                    {currentFolderName && (
                        <div className="bg-primary/5 p-4 rounded-2xl flex items-center justify-between border border-primary/10 shadow-inner group transition-all hover:bg-primary/[0.08]">
                            <div className="flex items-center gap-4">
                                <div className="h-12 w-12 rounded-2xl bg-primary/10 flex items-center justify-center border border-primary/10 shadow-sm transition-transform group-hover:scale-110">
                                    <Folder className="h-6 w-6 text-primary fill-primary/20" />
                                </div>
                                <div className="flex flex-col">
                                    <span className="text-[10px] uppercase font-black text-primary/60 leading-none mb-1.5 tracking-widest">Pasta Raiz Ativa</span>
                                    <span className="font-black text-sm text-foreground tracking-tight">{currentFolderName}</span>
                                </div>
                            </div>
                            <Button variant="ghost" size="icon" className="h-10 w-10 text-muted-foreground hover:bg-background/80 hover:text-primary" asChild>
                                <a href={`https://drive.google.com/open?id=${currentFolderId}`} target="_blank" rel="noreferrer">
                                    <ExternalLink className="h-4 w-4" />
                                </a>
                            </Button>
                        </div>
                    )}
                </CardContent>
            </Card>

            {currentFolderName && path.length > 0 && (
                <Card className="bg-card border-border shadow-md overflow-hidden rounded-2xl border-t-4 border-t-primary">
                    <CardHeader className="py-5 bg-background border-b border-border/50">
                        <div className="flex flex-col gap-4">
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col gap-1">
                                    <CardTitle className="text-md font-black flex items-center gap-2 tracking-tight">
                                        Explorador de Arquivos
                                    </CardTitle>
                                    <CardDescription className="text-[11px] font-medium">Gerencie o conte├║do do seu Drive conectado.</CardDescription>
                                </div>
                                <Button
                                    variant="outline"
                                    size="sm"
                                    className="h-8 text-[10px] font-black uppercase tracking-widest gap-2 bg-background/50 backdrop-blur-sm border-border/50 hover:bg-primary/5 hover:text-primary transition-all rounded-lg"
                                    onClick={() => loadContents(activeFolder?.id || currentFolderId!)}
                                    disabled={isListingContents}
                                >
                                    <RefreshCw className={`h-3 w-3 ${isListingContents ? 'animate-spin' : ''}`} />
                                    Atualizar
                                </Button>
                            </div>

                            <div className="flex items-center gap-1.5 p-1.5 bg-secondary/30 rounded-xl border border-border/30 overflow-x-auto no-scrollbar">
                                {path.map((folder, index) => (
                                    <div key={folder.id} className="flex items-center gap-1.5 shrink-0">
                                        <button
                                            onClick={() => navigateTo(folder, true)}
                                            className={`text-[11px] font-bold px-3 py-1.5 rounded-lg transition-all flex items-center gap-2 ${index === path.length - 1 ? 'bg-background text-primary shadow-sm border border-border/50' : 'text-muted-foreground hover:text-foreground hover:bg-background/50'}`}
                                        >
                                            {index === 0 && <HardDrive className="h-3 w-3" />}
                                            {folder.name}
                                        </button>
                                        {index < path.length - 1 && <span className="text-muted-foreground/30 font-black">/</span>}
                                    </div>
                                ))}
                            </div>
                        </div>
                    </CardHeader>
                    <CardContent className="p-0 bg-background/50">
                        <div className="px-6 py-5 bg-secondary/5 border-b border-border/30 backdrop-blur-sm flex gap-2">
                            <div className="relative flex-1">
                                <Plus className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground/60" />
                                <Input
                                    placeholder="Nome da subpasta (ex: Recibos 2024)..."
                                    className="h-10 text-xs bg-background pl-9 border-border/50 rounded-xl font-medium focus-visible:ring-primary/20"
                                    value={newFolderName}
                                    onChange={(e) => setNewFolderName(e.target.value)}
                                    onKeyDown={(e) => e.key === 'Enter' && handleCreateSubfolder()}
                                />
                            </div>
                            <Button size="sm" className="h-10 gap-2 font-black px-6 text-[11px] uppercase tracking-widest rounded-xl transition-all shadow-lg shadow-primary/10 hover:shadow-primary/20 active:scale-95" onClick={() => handleCreateSubfolder()}>
                                Nova Pasta
                            </Button>
                        </div>

                        <div className="min-h-[300px] max-h-[500px] overflow-y-auto divide-y divide-border/20 custom-scrollbar">
                            {isListingContents ? (
                                <div className="p-20 text-center text-muted-foreground flex flex-col items-center gap-4">
                                    <RefreshCw className="h-8 w-8 animate-spin text-primary opacity-20" />
                                    <p className="text-[11px] font-black uppercase tracking-widest opacity-40">Carregando arquivos...</p>
                                </div>
                            ) : contents.length === 0 ? (
                                <div className="p-20 text-center flex flex-col items-center gap-3">
                                    <div className="h-16 w-16 rounded-3xl bg-secondary/20 flex items-center justify-center mb-2">
                                        <Folder className="h-8 w-8 text-muted-foreground/20" />
                                    </div>
                                    <p className="text-xs text-muted-foreground font-black uppercase tracking-widest opacity-40">Esta pasta est├í vazia</p>
                                    <p className="text-[10px] text-muted-foreground/60 font-medium max-w-[200px] mx-auto">Use o campo acima para criar sua primeira subpasta.</p>
                                </div>
                            ) : (
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 p-4 gap-3">
                                    {contents.map((item) => (
                                        <div
                                            key={item.id}
                                            className="group p-3 bg-background border border-border/50 rounded-2xl hover:border-primary/30 hover:shadow-md hover:bg-primary/[0.02] transition-all cursor-pointer flex items-center justify-between"
                                            onClick={() => item.mimeType === 'application/vnd.google-apps.folder' && navigateTo(item)}
                                        >
                                            <div className="flex items-center gap-3 min-w-0">
                                                <div className={`h-10 w-10 rounded-xl flex items-center justify-center shrink-0 border transition-all group-hover:scale-110 ${item.mimeType === 'application/vnd.google-apps.folder' ? 'bg-blue-500/10 border-blue-500/10' : 'bg-muted/30 border-border/50'}`}>
                                                    {item.mimeType === 'application/vnd.google-apps.folder' ? (
                                                        <Folder className="h-5 w-5 text-blue-500 fill-blue-500/20" />
                                                    ) : (
                                                        <FileIcon className="h-5 w-5 text-muted-foreground" />
                                                    )}
                                                </div>
                                                <div className="flex flex-col min-w-0">
                                                    <span className="text-[13px] font-bold text-foreground/80 truncate pr-2 tracking-tight group-hover:text-foreground transition-colors">{item.name}</span>
                                                    <span className="text-[9px] font-bold uppercase tracking-widest text-muted-foreground/50">
                                                        {item.mimeType === 'application/vnd.google-apps.folder' ? 'Pasta' : 'Arquivo'}
                                                    </span>
                                                </div>
                                            </div>
                                            <Button variant="ghost" size="icon" className="h-8 w-8 rounded-full bg-secondary/10 opacity-0 group-hover:opacity-100 transition-all hover:bg-primary/10 hover:text-primary" asChild onClick={(e) => e.stopPropagation()}>
                                                <a href={`https://drive.google.com/open?id=${item.id}`} target="_blank" rel="noreferrer">
                                                    <ExternalLink className="h-3.5 w-3.5" />
                                                </a>
                                            </Button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </CardContent>
                </Card>
            )}
        </div>
    );
}

import { useState } from "react";
import { Dialog, DialogContent } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useChurch } from "@/contexts/ChurchContext";
import { Church, Loader2, PlusCircle, LogIn, X, LogOut } from "lucide-react";
import { supabase } from "@/lib/supabase";
import { toast } from "sonner";

export function OnboardingModal() {
  const { user, profile, organization, loading, setHasSeenOnboarding, hasSeenOnboarding, logout } = useChurch();
  const [churchName, setChurchName] = useState("");
  const [joinCode, setJoinCode] = useState("");
  const [onboardingType, setOnboardingType] = useState<"create" | "join" | null>(null);
  const [isCreating, setIsCreating] = useState(false);

  // Se estiver carregando os dados do contexto, n├úo mostra o onboarding ainda
  if (loading) return null;
  // Se o usu├írio j├í ignorou ou tem igreja, pula
  if (hasSeenOnboarding || organization || profile?.organization_id) return null;
  if (!user) return null;

  const handleCreateChurch = async () => {
    // ... same logic ...
    if (!churchName) {
      toast.error("Por favor, informe o nome da sua igreja");
      return;
    }

    setIsCreating(true);
    try {
      const { data: org, error: orgError } = await (supabase
        .from("organizations") as any)
        .insert([{ name: churchName }])
        .select()
        .single();

      if (orgError) throw orgError;

      const { error: profileError } = await (supabase
        .from("profiles") as any)
        .update({ organization_id: org.id, role: 'admin' })
        .eq("id", user.id);

      if (profileError) throw profileError;

      const defaultCategories = [
        { name: "Oferta", type: "income", color: "#10b981", organization_id: org.id },
        { name: "D├¡zimo", type: "income", color: "#10b981", organization_id: org.id },
        { name: "├ügua", type: "expense", color: "#f43f5e", organization_id: org.id },
        { name: "Energia", type: "expense", color: "#f43f5e", organization_id: org.id },
      ];

      await (supabase.from("categories") as any).insert(defaultCategories);

      setHasSeenOnboarding(true);
      toast.success("Igreja criada com sucesso!");
      setTimeout(() => window.location.reload(), 100);
    } catch (error) {
      toast.error("Erro ao configurar igreja");
    } finally {
      setIsCreating(false);
    }
  };

  const handleJoinChurch = async () => {
    if (!joinCode) {
      toast.error("Por favor, informe o c├│digo da igreja");
      return;
    }

    setIsCreating(true);
    try {
      const { data: org, error: orgError } = await (supabase
        .from("organizations") as any)
        .select("id, name")
        .eq("id", joinCode.trim())
        .single();

      if (orgError || !org) {
        toast.error("C├│digo de igreja inv├ílido");
        return;
      }

      const { error: profileError } = await (supabase
        .from("profiles") as any)
        .update({ organization_id: org.id, role: 'viewer' })
        .eq("id", user.id);

      if (profileError) throw profileError;

      setHasSeenOnboarding(true);
      toast.success(`Voc├¬ entrou na igreja ${org.name}!`);
      setTimeout(() => window.location.reload(), 100);
    } catch (error) {
      toast.error("Erro ao entrar na igreja");
    } finally {
      setIsCreating(false);
    }
  };

  const handleClose = () => {
    setHasSeenOnboarding(true);
  };

  return (
    <Dialog open={true} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-md bg-card border-none p-0 overflow-hidden rounded-3xl shadow-2xl" onPointerDownOutside={(e) => e.preventDefault()}>
        <div className="relative p-8 flex flex-col items-center text-center space-y-6">
          <button
            onClick={handleClose}
            className="absolute right-4 top-4 p-2 hover:bg-secondary/50 rounded-full transition-colors text-muted-foreground z-50 border border-border"
          >
            <X className="h-5 w-5" />
          </button>

          <div className="h-20 w-20 rounded-3xl bg-primary/10 flex items-center justify-center">
            <Church className="h-10 w-10 text-primary" />
          </div>

          <div className="space-y-2">
            <h2 className="text-2xl font-black tracking-tight text-foreground">Configura├º├úo de Igreja</h2>
            <p className="text-[14px] text-muted-foreground leading-relaxed px-4">
              Identificamos que sua conta ainda n├úo possui uma igreja vinculada. Como deseja prosseguir?
            </p>
          </div>

          {!onboardingType ? (
            <div className="grid grid-cols-1 gap-4 w-full">
              <Button
                variant="outline"
                className="h-24 flex flex-col items-center justify-center gap-2 border-2 border-dashed hover:border-primary hover:bg-primary/5 transition-all group rounded-2xl"
                onClick={() => setOnboardingType("create")}
              >
                <div className="flex items-center gap-2 font-black text-foreground uppercase tracking-widest text-xs">
                  <PlusCircle className="h-5 w-5 text-primary" /> Criar Minha Igreja
                </div>
                <span className="text-[11px] text-muted-foreground font-medium">Ideal para pastores que est├úo come├ºando no Mordus.</span>
              </Button>
              <Button
                variant="outline"
                className="h-24 flex flex-col items-center justify-center gap-2 border-2 border-dashed hover:border-primary hover:bg-primary/5 transition-all group rounded-2xl"
                onClick={() => setOnboardingType("join")}
              >
                <div className="flex items-center gap-2 font-black text-foreground uppercase tracking-widest text-xs">
                  <LogIn className="h-5 w-5 text-primary" /> Entrar em Igreja Existente
                </div>
                <span className="text-[11px] text-muted-foreground font-medium">Use o c├│digo fornecido pelo seu administrador.</span>
              </Button>

              <div className="pt-4 flex flex-col gap-2">
                <Button
                  variant="ghost"
                  className="text-xs text-muted-foreground hover:text-destructive h-8"
                  onClick={logout}
                >
                  <LogOut className="h-3 w-3 mr-2" /> Sair da conta
                </Button>
              </div>
            </div>
          ) : onboardingType === "create" ? (
            <div className="w-full space-y-4 text-left">
              <div className="space-y-2">
                <Label htmlFor="church-name" className="text-xs font-bold text-muted-foreground ml-1 text-center block">NOME DA SUA IGREJA</Label>
                <Input
                  id="church-name"
                  placeholder="Ex: Igreja Batista Central"
                  value={churchName}
                  onChange={(e) => setChurchName(e.target.value)}
                  className="h-12 bg-secondary/20 border-border/40 rounded-xl"
                />
              </div>
              <div className="flex gap-3 pt-2">
                <Button variant="outline" className="flex-1 h-12 rounded-xl" onClick={() => setOnboardingType(null)}>Voltar</Button>
                <Button className="flex-[2] h-12 rounded-xl font-bold" onClick={handleCreateChurch} disabled={isCreating}>
                  {isCreating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                  Configurar Agora
                </Button>
              </div>
            </div>
          ) : (
            <div className="w-full space-y-4 text-left">
              <div className="space-y-2">
                <Label htmlFor="join-code" className="text-xs font-bold text-muted-foreground ml-1 text-center block">C├ôDIGO DE ACESSO</Label>
                <Input
                  id="join-code"
                  placeholder="Cole o ID da igreja aqui"
                  value={joinCode}
                  onChange={(e) => setJoinCode(e.target.value)}
                  className="h-12 bg-secondary/20 border-border/40 font-mono text-xs rounded-xl text-center"
                />
              </div>
              <div className="flex gap-3 pt-2">
                <Button variant="outline" className="flex-1 h-12 rounded-xl" onClick={() => setOnboardingType(null)}>Voltar</Button>
                <Button className="flex-[2] h-12 rounded-xl font-bold" onClick={handleJoinChurch} disabled={isCreating}>
                  {isCreating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                  Vincular Agora
                </Button>
              </div>
              <p className="text-[10px] text-center text-muted-foreground italic">
                Ao entrar em uma igreja existente, voc├¬ come├ºar├í como 'Visualizador'.
              </p>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Plus, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { DatePicker } from "@/components/ui/date-picker";
import { supabase } from "@/lib/supabase";
import { useChurch } from "@/contexts/ChurchContext";
import { toast } from "sonner";
import { parseISO, format as formatDateFns } from "date-fns";

const OCCASIONS = [
    "Culto de Domingo (Manh├ú)",
    "Culto de Domingo (Noite)",
    "Culto de Ensino",
    "Escola Dominical",
    "Reuni├úo de Ora├º├úo",
    "C├¡rculo de Ora├º├úo",
    "Santa Ceia",
    "Confer├¬ncia",
    "Evento Especial",
    "Outros"
];

export function QuickEntryDialog({ onSuccess }: { onSuccess?: () => void }) {
    const { organization } = useChurch();
    const [open, setOpen] = useState(false);
    const [loading, setLoading] = useState(false);
    const [categories, setCategories] = useState<{ id: string; name: string; type: string }[]>([]);

    const [form, setForm] = useState({
        date: new Date().toLocaleDateString('en-CA'),
        description: "",
        amount: "",
        category_id: "",
        type: "income" as "income" | "expense",
        payment_method: "Dinheiro",
        payment_method_id: undefined as string | undefined,
        occasion: ""
    });

    useEffect(() => {
        if (open && organization?.id) {
            fetchCategories();
        }
    }, [open, organization?.id]);

    const fetchCategories = async () => {
        const { data } = await supabase
            .from("categories")
            .select("id, name, type")
            .eq("organization_id", organization!.id);
        setCategories(data || []);
    };

    const handleSave = async () => {
        if (!form.description || !form.amount || !organization?.id) {
            toast.error("Preencha os campos obrigat├│rios");
            return;
        }

        setLoading(true);
        try {
            const { error } = await supabase.from("transactions").insert([{
                organization_id: organization.id,
                type: form.type,
                category_id: form.category_id || null,
                amount: parseFloat(form.amount),
                date: form.date,
                description: form.description,
                payment_method: form.payment_method,
                payment_method_id: form.payment_method_id || null,
                occasion: form.occasion || null
            }]);

            if (error) throw error;

            toast.success("Lan├ºamento r├ípido realizado!");
            setOpen(false);
            setForm({
                date: new Date().toLocaleDateString('en-CA'),
                description: "",
                amount: "",
                category_id: "",
                type: "income",
                payment_method: "Dinheiro",
                payment_method_id: undefined,
                occasion: ""
            });
            if (onSuccess) onSuccess();
        } catch (err) {
            toast.error("Erro ao salvar lan├ºamento");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                <Button variant="outline" className="h-9 px-4 text-xs font-semibold gap-2 border-primary/30 hover:bg-primary/10 shadow-sm text-primary hover:text-primary transition-all">
                    <Plus className="h-4 w-4" />
                    Lan├ºamento R├ípido
                </Button>
            </DialogTrigger>
            <DialogContent className="bg-card border-border sm:max-w-[400px]">
                <DialogHeader>
                    <DialogTitle>Lan├ºamento R├ípido</DialogTitle>
                </DialogHeader>
                <div className="grid gap-4 py-4">
                    <div className="flex bg-secondary/30 p-1 rounded-lg">
                        <button
                            onClick={() => setForm({ ...form, type: 'income' })}
                            className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${form.type === 'income' ? 'bg-background text-success shadow-sm' : 'text-muted-foreground'}`}
                        >
                            Entrada
                        </button>
                        <button
                            onClick={() => setForm({ ...form, type: 'expense' })}
                            className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${form.type === 'expense' ? 'bg-background text-destructive shadow-sm' : 'text-muted-foreground'}`}
                        >
                            Sa├¡da
                        </button>
                    </div>

                    <div className="space-y-2">
                        <Label className="text-[12px]">Data</Label>
                        <DatePicker
                            date={form.date ? new Date(form.date + 'T12:00:00') : undefined}
                            onChange={(date) => setForm({
                                ...form,
                                date: date ? formatDateFns(date, "yyyy-MM-dd") : ""
                            })}
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-2">
                            <Label className="text-[12px]">Valor (R$)</Label>
                            <Input type="number" step="0.01" placeholder="0,00" value={form.amount} onChange={(e) => setForm({ ...form, amount: e.target.value })} />
                        </div>
                        <div className="space-y-2">
                            <Label className="text-[12px]">Categoria</Label>
                            <Select value={form.category_id} onValueChange={(v) => setForm({ ...form, category_id: v })}>
                                <SelectTrigger><SelectValue placeholder="Selecione" /></SelectTrigger>
                                <SelectContent>
                                    {categories.filter(c => c.type === form.type).map(c => (
                                        <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-2">
                            <Label className="text-[12px]">Ocasi├úo / Evento</Label>
                            <Select
                                value={form.occasion}
                                onValueChange={(v) => {
                                    setForm({
                                        ...form,
                                        occasion: v,
                                        description: v !== "Outros" ? v : form.description
                                    });
                                }}
                            >
                                <SelectTrigger className="h-10 text-[11px]"><SelectValue placeholder="Ocasi├úo" /></SelectTrigger>
                                <SelectContent>
                                    {OCCASIONS.map(oc => (
                                        <SelectItem key={oc} value={oc}>{oc}</SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="space-y-2">
                            <Label className="text-[12px]">Meio</Label>
                            <Select
                                value={form.payment_method_id || form.payment_method}
                                onValueChange={(v) => {
                                    const selected = categories.find(c => c.id === v);
                                    setForm({
                                        ...form,
                                        payment_method_id: selected ? v : undefined,
                                        payment_method: selected ? selected.name : v
                                    });
                                }}
                            >
                                <SelectTrigger className="h-10 text-[11px]"><SelectValue placeholder="Meio" /></SelectTrigger>
                                <SelectContent>
                                    {categories.filter(c => c.type === 'method').map(c => (
                                        <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>
                                    ))}
                                    {/* Fallback para compatibilidade se n├úo houver din├ómicos ainda */}
                                    {categories.filter(c => c.type === 'method').length === 0 && (
                                        <>
                                            <SelectItem value="Dinheiro">Dinheiro</SelectItem>
                                            <SelectItem value="Pix">Pix</SelectItem>
                                            <SelectItem value="Cart├úo">Cart├úo</SelectItem>
                                        </>
                                    )}
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label className="text-[12px]">Descri├º├úo</Label>
                        <Input placeholder="Ex: Oferta de Culto" value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} />
                    </div>

                    <Button className="w-full mt-2 font-bold" onClick={handleSave} disabled={loading}>
                        {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                        Confirmar Lan├ºamento
                    </Button>
                </div>
            </DialogContent>
        </Dialog>
    );
}

import { useState, useEffect } from "react";
import { Plus, Trash2, Loader2, Calendar, FileText, Banknote, ChevronRight, ChevronLeft, CheckCircle2, AlertCircle, Upload, Eye, X, Repeat, PlusCircle, Save, ShoppingBag, Landmark, Briefcase } from "lucide-react";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from "@/components/ui/dialog";
import { Separator } from "@/components/ui/separator";
import { DatePicker } from "@/components/ui/date-picker";
import { supabase } from "@/lib/supabase";
import { useChurch } from "@/contexts/ChurchContext";
import { toast } from "sonner";
import { format as formatDateFns, addMonths } from "date-fns";
import { Card, CardContent } from "@/components/ui/card";
import { Switch } from "@/components/ui/switch";
import type { ReactNode } from "react";

const DEFAULT_OCCASIONS = [
    "Culto de Domingo (Manh├ú)",
    "Culto de Domingo (Noite)",
    "Culto de Ensino",
    "Escola Dominical",
    "Reuni├úo de Ora├º├úo",
    "Santa Ceia",
    "Evento Especial",
    "Outros"
];

const emptyItem = { category_id: "", amount: "", payment_method: "Dinheiro", payment_method_id: "", type: "income" as "income" | "expense", receipt_url: "", status: "" };
const emptyForm = { date: new Date().toLocaleDateString('en-CA'), description: "", event_id: "", occasion: "", items: [{ ...emptyItem }] };

interface TransactionsDialogProps {
    onSuccess?: () => void;
    trigger?: ReactNode;
    editingTransaction?: any;
    open?: boolean;
    onOpenChange?: (open: boolean) => void;
}

function formatCurrency(value: number) {
    return value.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}

export function TransactionsDialog({ onSuccess, trigger, editingTransaction, open: externalOpen, onOpenChange }: TransactionsDialogProps) {
    const { organization } = useChurch();
    const [internalOpen, setInternalOpen] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [currentStep, setCurrentStep] = useState(1);
    const [categories, setCategories] = useState<{ id: string; name: string; type: string }[]>([]);
    const [events, setEvents] = useState<{ id: string; name: string }[]>([]);
    const [form, setForm] = useState(emptyForm);
    const [isInstallmentMode, setIsInstallmentMode] = useState(false);
    const [installmentCount, setInstallmentCount] = useState(2);
    const [selectedIntent, setSelectedIntent] = useState<'income' | 'expense' | 'sale' | 'asset' | null>(null);
    const [isCreatingCategory, setIsCreatingCategory] = useState(false);
    const [newCategoryName, setNewCategoryName] = useState("");
    const [newCategoryType, setNewCategoryType] = useState<"income" | "expense" | "method" | "occasion" | "event">("income");
    const [closures, setClosures] = useState<{ end_date: string }[]>([]);

    const open = externalOpen !== undefined ? externalOpen : internalOpen;
    const setOpen = onOpenChange || setInternalOpen;

    useEffect(() => {
        if (open && organization?.id) {
            fetchCategories();
            fetchEvents();
            fetchClosures();
            if (editingTransaction) {
                setForm({
                    date: editingTransaction.date,
                    description: editingTransaction.description,
                    event_id: editingTransaction.event_id || "",
                    occasion: editingTransaction.occasion || "",
                    items: [{
                        type: editingTransaction.type,
                        category_id: editingTransaction.category_id || "",
                        amount: String(editingTransaction.amount),
                        payment_method: editingTransaction.payment_method || "Dinheiro",
                        payment_method_id: editingTransaction.payment_method_id || "",
                        receipt_url: editingTransaction.receipt_url || "",
                        status: editingTransaction.status || ""
                    }]
                });
                setSelectedIntent(editingTransaction.type);
                setCurrentStep(2);
            } else {
                setForm(emptyForm);
                setSelectedIntent(null);
                setCurrentStep(1);
            }
        }
    }, [open, organization?.id, editingTransaction]);

    const fetchCategories = async () => {
        const { data: cats } = await supabase
            .from("categories")
            .select("id, name, type")
            .eq("organization_id", organization!.id);
        setCategories(cats || []);
    };

    const fetchEvents = async () => {
        const { data: evts } = await supabase
            .from("events")
            .select("id, name")
            .eq("organization_id", organization!.id)
            .gte("date", new Date(new Date().setMonth(new Date().getMonth() - 1)).toISOString())
            .order("date", { ascending: false });
        setEvents(evts || []);
    };

    const fetchClosures = async () => {
        if (!organization?.id) return;
        const { data } = await supabase
            .from("monthly_closures")
            .select("end_date")
            .eq("organization_id", organization.id)
            .eq("status", "closed");
        setClosures(data || []);
    };

    const isMonthClosed = (dateStr: string) => {
        if (!dateStr) return false;
        return closures.some(c => dateStr <= c.end_date);
    };

    const addItem = () => {
        setForm(prev => ({
            ...prev,
            items: [...prev.items, { ...emptyItem }]
        }));
    };

    const removeItem = (index: number) => {
        if (form.items.length <= 1) return;
        setForm(prev => ({
            ...prev,
            items: prev.items.filter((_, i) => i !== index)
        }));
    };

    const updateItem = (index: number, field: string | any, value?: string) => {
        const newItems = [...form.items];

        if (typeof field === 'object') {
            newItems[index] = { ...newItems[index], ...field };
        } else if (field === "payment_method" && value !== "") {
            const selectedMethod = categories.find(c => c.id === value && c.type === 'method');
            if (selectedMethod) {
                newItems[index] = { ...newItems[index], payment_method: selectedMethod.name, payment_method_id: selectedMethod.id } as any;
            } else {
                newItems[index] = { ...newItems[index], payment_method: value, payment_method_id: "" } as any;
            }
        } else {
            newItems[index] = { ...newItems[index], [field]: value } as any;
        }
        setForm({ ...form, items: newItems });
    };

    const applyPreset = (index: number, type: 'income' | 'expense', categoryName: string) => {
        const category = categories.find(c => c.type === type && c.name.toLowerCase().includes(categoryName.toLowerCase()));
        const method = categories.find(c => c.type === 'method' && c.name.toLowerCase().includes('dinheiro')) || { id: "", name: "Dinheiro" };

        updateItem(index, {
            type,
            category_id: category?.id || "",
            payment_method: method.name,
            payment_method_id: method.id
        });
        toast.success(`Preset "${categoryName}" aplicado!`);
    };

    const handleUpload = async (index: number, file: File) => {
        try {
            setIsSaving(true);
            const fileExt = file.name.split('.').pop();
            const fileName = `${crypto.randomUUID()}.${fileExt}`;
            const filePath = `${organization!.id}/${fileName}`;

            const { error: uploadError } = await supabase.storage
                .from('receipts')
                .upload(filePath, file);

            if (uploadError) throw uploadError;

            const { data: { publicUrl } } = supabase.storage
                .from('receipts')
                .getPublicUrl(filePath);

            updateItem(index, "receipt_url", publicUrl);
            toast.success("Comprovante enviado!");
        } catch (error: any) {
            toast.error("Erro no upload: " + error.message);
        } finally {
            setIsSaving(false);
        }
    };

    const validateStep = (step: number) => {
        if (step === 1) {
            if (!selectedIntent) {
                toast.error("Selecione uma inten├º├úo para continuar");
                return false;
            }
        }
        if (step === 2) {
            if (!form.description || !form.date) {
                toast.error("Preencha a data e a descri├º├úo principal");
                return false;
            }
        }
        if (step === 3) {
            const validItems = form.items.filter(item => item.amount && parseFloat(item.amount) > 0 && item.category_id);
            if (validItems.length === 0) {
                toast.error("Adicione pelo menos um item com categoria e valor v├ílido");
                return false;
            }
        }
        return true;
    };

    const handleQuickCategoryCreate = async (index: number, specificType?: string) => {
        const typeToUse = specificType || newCategoryType;
        if (!newCategoryName || !organization?.id) return;
        try {
            if (typeToUse === 'event') {
                const { data, error } = await supabase
                    .from("events")
                    .insert([{
                        name: newCategoryName,
                        organization_id: organization.id,
                        date: form.date || new Date().toISOString().split('T')[0],
                        type: 'Evento'
                    }])
                    .select()
                    .single();
                if (error) throw error;
                setEvents(prev => [...prev, data]);
                setForm({ ...form, event_id: data.id });
            } else {
                const { data, error } = await supabase
                    .from("categories")
                    .insert([{
                        name: newCategoryName,
                        type: typeToUse,
                        organization_id: organization.id
                    }])
                    .select()
                    .single();
                if (error) throw error;

                if (typeToUse === 'occasion') {
                    setCategories(prev => [...prev, data]);
                    setForm({ ...form, occasion: data.name });
                } else if (typeToUse === 'method') {
                    setCategories(prev => [...prev, data]);
                    updateItem(index, { payment_method: data.name, payment_method_id: data.id });
                } else {
                    setCategories(prev => [...prev, data]);
                    updateItem(index, "category_id", data.id);
                }
            }

            setNewCategoryName("");
            setIsCreatingCategory(false);
            toast.success("Registrado com sucesso!");
        } catch (err: any) {
            console.error(err);
            toast.error(`Erro ao registrar: ${err.message || 'Erro desconhecido'}`);
        }
    };

    const nextStep = () => {
        if (currentStep === 1 && !selectedIntent) {
            toast.error("Selecione uma inten├º├úo para continuar");
            return;
        }
        if (validateStep(currentStep)) {
            setCurrentStep(prev => prev + 1);
        }
    };

    const prevStep = () => {
        setCurrentStep(prev => prev - 1);
    };

    const handleSave = async () => {
        if (!validateStep(2)) return;

        const validItems = form.items.filter(item => item.amount && parseFloat(item.amount) > 0);
        const eventId = (form.event_id && form.event_id !== "none") ? form.event_id : null;

        setIsSaving(true);
        try {
            if (editingTransaction?.id) {
                const item = form.items[0];
                const payload = {
                    organization_id: organization!.id,
                    type: item.type,
                    category_id: item.category_id || null,
                    amount: parseFloat(item.amount),
                    date: form.date,
                    description: form.description,
                    payment_method: item.payment_method,
                    payment_method_id: item.payment_method_id || null,
                    event_id: eventId,
                    occasion: form.occasion || null,
                    receipt_url: item.receipt_url || null,
                    status: item.status || (new Date(form.date + 'T12:00:00') <= new Date() ? 'completed' : 'pending'),
                    competence_date: form.date // Em edi├º├Áes simples, a compet├¬ncia ├® a data do lan├ºamento
                };
                const { error } = await supabase.from("transactions").update(payload).eq("id", editingTransaction.id);
                if (error) throw error;
                toast.success("Lan├ºamento atualizado");
            } else if (isInstallmentMode) {
                // NOVO SISTEMA DE PARCELAMENTO (ROBUSTO)
                const occurrences = installmentCount;
                const totalAmount = validItems.reduce((acc, item) => acc + parseFloat(item.amount), 0);

                // 1. Criar a Compra Parcelada (Pai)
                const { data: purchase, error: purchaseError } = await supabase
                    .from("installment_purchases")
                    .insert([{
                        organization_id: organization!.id,
                        description: form.description,
                        total_amount: totalAmount,
                        category_id: validItems[0].category_id || null,
                        payment_method_id: validItems[0].payment_method_id || null
                    }])
                    .select()
                    .single();

                if (purchaseError) throw purchaseError;

                const installmentPayloads: any[] = [];
                const transactionPayloads: any[] = [];

                for (let i = 0; i < occurrences; i++) {
                    const competenceMonth = addMonths(new Date(form.date + 'T12:00:00'), i);
                    const competenceDateStr = formatDateFns(competenceMonth, "yyyy-MM-01");
                    const dueDateStr = formatDateFns(competenceMonth, "yyyy-MM-dd");
                    const amountPerInstallment = totalAmount / occurrences;

                    // Status autom├ítico baseado na data
                    const isTodayOrPast = new Date(dueDateStr + 'T12:00:00') <= new Date();
                    const status = isTodayOrPast ? 'PAGA' : 'PENDENTE';

                    const instPayload = {
                        purchase_id: purchase.id,
                        organization_id: organization!.id,
                        competence_date: competenceDateStr,
                        due_date: dueDateStr,
                        status: status,
                        amount: amountPerInstallment,
                        payment_date: isTodayOrPast ? new Date().toISOString() : null,
                        installment_number: i + 1,
                        total_installments: occurrences
                    };

                    installmentPayloads.push(instPayload);
                }

                const { data: createdInstallments, error: instError } = await supabase
                    .from("installments")
                    .insert(installmentPayloads)
                    .select();

                if (instError) throw instError;

                // 2. Se a parcela for marcada como PAGA, criamos o lan├ºamento no caixa (transactions)
                for (const inst of createdInstallments) {
                    if (inst.status === 'PAGA') {
                        transactionPayloads.push({
                            organization_id: organization!.id,
                            type: validItems[0].type,
                            category_id: validItems[0].category_id || null,
                            amount: inst.amount,
                            date: inst.due_date, // Data em que o dinheiro saiu/entrou (neste caso, simplificado para o vencimento se j├í passou)
                            description: `[P ${String(installmentPayloads.findIndex(p => p.due_date === inst.due_date) + 1).padStart(2, '0')}/${String(occurrences).padStart(2, '0')}] ${form.description}`,
                            payment_method: validItems[0].payment_method,
                            payment_method_id: validItems[0].payment_method_id || null,
                            installment_id: inst.id,
                            competence_date: inst.competence_date,
                            status: 'completed'
                        });
                    }
                }

                if (transactionPayloads.length > 0) {
                    const { error: txError } = await supabase.from("transactions").insert(transactionPayloads);
                    if (txError) throw txError;
                }

                toast.success(`${occurrences} parcelas geradas no sistema robusto!`);
            } else {
                // LAN├çAMENTO SIMPLES (N├âO PARCELADO)
                const payloads = validItems.map(item => ({
                    organization_id: organization!.id,
                    type: item.type,
                    category_id: item.category_id || null,
                    amount: parseFloat(item.amount),
                    date: form.date,
                    description: form.description,
                    payment_method: item.payment_method,
                    payment_method_id: item.payment_method_id || null,
                    event_id: eventId as any,
                    occasion: form.occasion || null,
                    receipt_url: item.receipt_url || null,
                    status: new Date(form.date + 'T12:00:00') <= new Date() ? 'completed' : 'pending',
                    competence_date: form.date // Por padr├úo, a compet├¬ncia ├® a data do lan├ºamento
                }));

                const { error } = await supabase.from("transactions").insert(payloads as any);
                if (error) throw error;

                // Integra├º├úo Autom├ítica com Patrim├┤nio
                if (selectedIntent === 'asset') {
                    const totalValue = validItems.reduce((acc, item) => acc + parseFloat(item.amount), 0);
                    const { error: assetError } = await supabase.from("assets").insert([{
                        organization_id: organization!.id,
                        name: form.description,
                        description: `Adquirido via lan├ºamento financeiro: ${form.description}`,
                        value: totalValue,
                        acquisition_date: form.date,
                        condition: 'Novo',
                        type: 'Equipamento/M├│vel'
                    }]);
                    if (assetError) console.error("Erro ao registrar no patrim├┤nio:", assetError);
                }

                toast.success(`${payloads.length} lan├ºamentos criados com sucesso!`);
            }

            setOpen(false);
            if (onSuccess) onSuccess();
        } catch (err) {
            console.error(err);
            toast.error("Erro ao salvar lan├ºamento");
        } finally {
            setIsSaving(false);
        }
    };

    const totals = form.items.reduce((acc, item) => {
        const val = parseFloat(item.amount) || 0;
        if (item.type === 'income') acc.income += val;
        else acc.expense += val;
        return acc;
    }, { income: 0, expense: 0 });

    return (
        <Dialog open={open} onOpenChange={(o) => {
            setOpen(o);
            if (!o) setCurrentStep(1);
        }}>
            {trigger && <DialogTrigger asChild>{trigger}</DialogTrigger>}
            <DialogContent className="sm:max-w-xl bg-card border-border p-0 overflow-hidden shadow-2xl ring-1 ring-primary/10">
                <div className="bg-gradient-to-r from-primary/10 via-background to-primary/5 p-6 border-b border-border/50">
                    <div className="flex items-center gap-3 mb-4">
                        <div className="h-10 w-10 rounded-2xl bg-primary/10 border border-primary/20 flex items-center justify-center shadow-inner">
                            <Banknote className="h-5 w-5 text-primary" />
                        </div>
                        <div>
                            <DialogTitle className="text-xl font-bold tracking-tight">
                                {editingTransaction ? "Editar Lan├ºamento" : "Assistente de Lan├ºamento"}
                            </DialogTitle>
                            <p className="text-muted-foreground text-[11px] font-medium uppercase tracking-widest mt-0.5">
                                Passo {currentStep} de 3
                            </p>
                        </div>
                    </div>

                    <div className="flex items-center gap-2">
                        {[1, 2, 3].map((s) => (
                            <div key={s} className="flex-1 flex items-center gap-2">
                                <div className={`h-1.5 flex-1 rounded-full transition-all duration-500 ${currentStep >= s ? "bg-primary shadow-[0_0_8px_rgba(var(--primary),0.4)]" : "bg-secondary"}`} />
                            </div>
                        ))}
                    </div>
                </div>

                <div className="p-6 max-h-[70vh] overflow-y-auto custom-scrollbar">
                    {currentStep === 1 && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <div className="text-center space-y-1 mb-8">
                                <h3 className="text-lg font-bold tracking-tight">O que vamos registrar agora?</h3>
                                <p className="text-xs text-muted-foreground uppercase tracking-widest font-semibold opacity-70">Selecione o tipo de movimenta├º├úo</p>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                {[
                                    { id: 'income', label: 'Entrada', icon: Landmark, color: 'text-success bg-success/10 border-success/20', desc: 'D├¡zimos e Ofertas' },
                                    { id: 'expense', label: 'Sa├¡da', icon: ShoppingBag, color: 'text-destructive bg-destructive/10 border-destructive/20', desc: 'Contas e Pagamentos' },
                                    { id: 'sale', label: 'Venda / Evento', icon: Banknote, color: 'text-primary bg-primary/10 border-primary/20', desc: 'Cantina e Inscri├º├Áes' },
                                    { id: 'asset', label: 'Patrim├┤nio', icon: Briefcase, color: 'text-amber-600 bg-amber-500/10 border-amber-500/20', desc: 'Compras e Benfeitorias' }
                                ].map((intent) => (
                                    <button
                                        key={intent.id}
                                        onClick={() => {
                                            setSelectedIntent(intent.id as any);
                                            const type = (intent.id === 'income' || intent.id === 'sale') ? 'income' : 'expense';
                                            updateItem(0, "type", type);
                                            setCurrentStep(2);
                                        }}
                                        className={`group relative flex flex-col items-center p-6 rounded-[2.5rem] border-2 transition-all duration-300 hover:scale-[1.03] active:scale-95 ${selectedIntent === intent.id ? 'border-primary bg-primary/5 ring-4 ring-primary/5' : 'border-transparent bg-secondary/5 hover:bg-secondary/10'}`}
                                    >
                                        <div className={`h-14 w-14 rounded-3xl ${intent.color} flex items-center justify-center mb-4 shadow-sm group-hover:shadow-md transition-all`}>
                                            <intent.icon className="h-7 w-7" />
                                        </div>
                                        <span className="font-bold text-sm mb-1">{intent.label}</span>
                                        <span className="text-[10px] text-muted-foreground opacity-60 font-medium">{intent.desc}</span>
                                    </button>
                                ))}
                            </div>
                        </div>
                    )}

                    {currentStep === 2 && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
                            <div className="flex items-center gap-2 text-primary mb-2">
                                <Calendar className="h-4 w-4" />
                                <span className="text-xs font-bold uppercase tracking-wider">Contexto do Lan├ºamento</span>
                            </div>

                            <div className="grid gap-4">
                                <div className="space-y-2">
                                    <Label className="text-[13px] font-semibold">Data do Lan├ºamento</Label>
                                    <DatePicker
                                        date={form.date ? new Date(form.date + 'T12:00:00') : undefined}
                                        onChange={(date) => setForm({
                                            ...form,
                                            date: date ? formatDateFns(date, "yyyy-MM-dd") : ""
                                        })}
                                    />
                                    <p className="text-[10px] text-muted-foreground">Escolha o dia em que a movimenta├º├úo ocorreu na conta ou caixa.</p>
                                    {isMonthClosed(form.date) && (
                                        <div className="flex items-center gap-2 p-2 bg-orange-500/10 border border-orange-500/20 rounded-lg animate-in fade-in duration-300">
                                            <AlertCircle className="h-3.5 w-3.5 text-orange-600" />
                                            <p className="text-[10px] text-orange-700 font-medium">Este m├¬s j├í est├í fechado. Altera├º├Áes podem afetar o saldo inicial dos meses seguintes.</p>
                                        </div>
                                    )}
                                </div>

                                <Separator className="opacity-50" />

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <div className="flex items-center justify-between">
                                            <Label className="text-[11px] text-muted-foreground uppercase font-black tracking-tighter">Ocasi├úo Principal</Label>
                                            <Popover open={isCreatingCategory && newCategoryType === 'occasion'} onOpenChange={(o) => {
                                                setIsCreatingCategory(o);
                                                setNewCategoryType('occasion');
                                            }}>
                                                <PopoverTrigger asChild>
                                                    <button className="text-[10px] text-primary hover:underline flex items-center gap-1 font-bold">
                                                        <PlusCircle className="h-3 w-3" /> Criar nova
                                                    </button>
                                                </PopoverTrigger>
                                                <PopoverContent className="w-64 p-3 bg-card border-primary/20 shadow-xl" align="end">
                                                    <div className="space-y-2">
                                                        <p className="text-[10px] font-black uppercase text-primary">Nova Ocasi├úo (Tipo de Culto)</p>
                                                        <Input
                                                            placeholder="Ex: Culto de Jovens"
                                                            className="h-8 text-xs"
                                                            value={newCategoryName}
                                                            onChange={(e) => setNewCategoryName(e.target.value)}
                                                            onKeyDown={(e) => e.key === 'Enter' && handleQuickCategoryCreate(0, 'occasion')}
                                                            autoFocus
                                                        />
                                                        <Button
                                                            className="w-full h-8 text-[10px] font-bold gap-2"
                                                            size="sm"
                                                            onClick={() => handleQuickCategoryCreate(0, 'occasion')}
                                                        >
                                                            <Save className="h-3 w-3" /> Salvar Ocasi├úo
                                                        </Button>
                                                    </div>
                                                </PopoverContent>
                                            </Popover>
                                        </div>
                                        <Select
                                            value={form.occasion}
                                            onValueChange={(v) => {
                                                setForm({
                                                    ...form,
                                                    occasion: v,
                                                    description: (v !== "Outros" && v !== "none") ? v : form.description
                                                });
                                            }}
                                        >
                                            <SelectTrigger className="h-10 bg-secondary/10 border-border/50 rounded-xl"><SelectValue placeholder="Selecione o culto/evento" /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="none">Selecione...</SelectItem>
                                                {categories.filter(c => c.type === 'occasion').length > 0 ? (
                                                    categories.filter(c => c.type === 'occasion').map(oc => (
                                                        <SelectItem key={oc.id} value={oc.name}>{oc.name}</SelectItem>
                                                    ))
                                                ) : (
                                                    DEFAULT_OCCASIONS.map(oc => <SelectItem key={oc} value={oc}>{oc}</SelectItem>)
                                                )}
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    <div className="space-y-2">
                                        <div className="flex items-center justify-between">
                                            <Label className="text-[11px] text-muted-foreground uppercase font-black tracking-tighter">V├¡nculo (Agenda)</Label>
                                            <Popover open={isCreatingCategory && newCategoryType === 'event'} onOpenChange={(o) => {
                                                setIsCreatingCategory(o);
                                                setNewCategoryType('event');
                                            }}>
                                                <PopoverTrigger asChild>
                                                    <button className="text-[10px] text-primary hover:underline flex items-center gap-1 font-bold">
                                                        <PlusCircle className="h-3 w-3" /> Criar novo
                                                    </button>
                                                </PopoverTrigger>
                                                <PopoverContent className="w-64 p-3 bg-card border-primary/20 shadow-xl" align="end">
                                                    <div className="space-y-2">
                                                        <p className="text-[10px] font-black uppercase text-primary">Novo Evento na Agenda</p>
                                                        <Input
                                                            placeholder="Nome do Evento"
                                                            className="h-8 text-xs"
                                                            value={newCategoryName}
                                                            onChange={(e) => setNewCategoryName(e.target.value)}
                                                            onKeyDown={(e) => e.key === 'Enter' && handleQuickCategoryCreate(0, 'event')}
                                                            autoFocus
                                                        />
                                                        <Button
                                                            className="w-full h-8 text-[10px] font-bold gap-2"
                                                            size="sm"
                                                            onClick={() => handleQuickCategoryCreate(0, 'event')}
                                                        >
                                                            <Save className="h-3 w-3" /> Salvar Evento
                                                        </Button>
                                                    </div>
                                                </PopoverContent>
                                            </Popover>
                                        </div>
                                        <Select value={form.event_id} onValueChange={(v) => setForm({ ...form, event_id: v })}>
                                            <SelectTrigger className="h-10 bg-secondary/10 border-border/50 rounded-xl"><SelectValue placeholder="Vincular evento" /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="none">Sem v├¡nculo</SelectItem>
                                                {events.map((e) => <SelectItem key={e.id} value={e.id}>{e.name}</SelectItem>)}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <Label className="text-[13px] font-semibold">Descri├º├úo / T├¡tulo do Lote</Label>
                                    <div className="relative">
                                        <FileText className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground opacity-50" />
                                        <Input
                                            placeholder="Ex: Ofertas do Culto de Santa Ceia"
                                            className="h-10 pl-10 bg-secondary/10 focus:bg-background transition-colors"
                                            value={form.description}
                                            onChange={(e) => setForm({ ...form, description: e.target.value })}
                                        />
                                    </div>
                                </div>

                                {!editingTransaction && (
                                    <div className="p-4 bg-primary/5 rounded-2xl border border-primary/20 space-y-4">
                                        <div className="flex items-center justify-between">
                                            <div className="flex items-center gap-2">
                                                <Repeat className="h-4 w-4 text-primary" />
                                                <div className="flex flex-col">
                                                    <span className="text-xs font-bold uppercase tracking-wider">Lan├ºamento Parcelado</span>
                                                    <span className="text-[10px] text-muted-foreground italic">Gerar m├║ltiplas parcelas mensais automaticamente</span>
                                                </div>
                                            </div>
                                            <Switch
                                                checked={isInstallmentMode}
                                                onCheckedChange={setIsInstallmentMode}
                                                className="scale-90"
                                            />
                                        </div>

                                        {isInstallmentMode && (
                                            <div className="flex items-center gap-4 animate-in fade-in slide-in-from-top-2 duration-300">
                                                <div className="space-y-1.5 flex-1">
                                                    <Label className="text-[11px] font-bold uppercase text-muted-foreground">N├║mero de Parcelas</Label>
                                                    <Input
                                                        type="number"
                                                        min="2"
                                                        max="60"
                                                        value={installmentCount}
                                                        onChange={(e) => setInstallmentCount(Number(e.target.value))}
                                                        className="h-9 text-xs bg-background border-primary/20"
                                                    />
                                                </div>
                                                <div className="self-end pb-2">
                                                    <p className="text-[10px] text-muted-foreground leading-tight">
                                                        Ser├úo gerados <strong>{installmentCount}</strong> lan├ºamentos com intervalos de 1 m├¬s.
                                                    </p>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    )}

                    {currentStep === 3 && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
                            <div className="flex items-center justify-between mb-2">
                                <div className="flex items-center gap-2 text-primary">
                                    <Banknote className="h-4 w-4" />
                                    <span className="text-xs font-bold uppercase tracking-wider">Detalhamento Financeiro</span>
                                </div>
                                {!editingTransaction && (
                                    <Button variant="outline" size="sm" className="h-7 text-[10px] font-bold uppercase border-dashed hover:bg-primary/5 px-4" onClick={addItem}>
                                        <Plus className="h-3 w-3 mr-1" /> Item Adicional
                                    </Button>
                                )}
                            </div>

                            <div className="space-y-4">
                                {form.items.map((item, index) => (
                                    <div key={index} className="relative bg-secondary/5 rounded-[2rem] border border-border/50 p-6 pt-10 md:pt-6 transition-all hover:bg-secondary/10 shadow-sm group">
                                        {!editingTransaction && form.items.length > 1 && (
                                            <button
                                                onClick={() => removeItem(index)}
                                                className="absolute top-4 right-4 p-1.5 rounded-full bg-destructive/10 text-destructive hover:bg-destructive hover:text-white transition-all"
                                            >
                                                <Trash2 className="h-3.5 w-3.5" />
                                            </button>
                                        )}

                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                            <div className="space-y-1.5">
                                                <div className="flex items-center justify-between">
                                                    <Label className="text-[11px] text-muted-foreground uppercase font-black tracking-tighter">Categoria *</Label>
                                                    <Popover open={isCreatingCategory && newCategoryType === item.type} onOpenChange={(o) => {
                                                        setIsCreatingCategory(o);
                                                        setNewCategoryType(item.type);
                                                    }}>
                                                        <PopoverTrigger asChild>
                                                            <button className="text-[10px] text-primary hover:underline flex items-center gap-1 font-bold">
                                                                <PlusCircle className="h-3 w-3" /> Criar nova
                                                            </button>
                                                        </PopoverTrigger>
                                                        <PopoverContent className="w-64 p-3 bg-card border-primary/20 shadow-xl" align="end">
                                                            <div className="space-y-2">
                                                                <p className="text-[10px] font-black uppercase text-primary">Nova Categoria de {item.type === 'income' ? 'Entrada' : 'Sa├¡da'}</p>
                                                                <Input
                                                                    placeholder="Nome da categoria"
                                                                    className="h-8 text-xs"
                                                                    value={newCategoryName}
                                                                    onChange={(e) => setNewCategoryName(e.target.value)}
                                                                    onKeyDown={(e) => e.key === 'Enter' && handleQuickCategoryCreate(index)}
                                                                    autoFocus
                                                                />
                                                                <Button
                                                                    className="w-full h-8 text-[10px] font-bold gap-2"
                                                                    size="sm"
                                                                    onClick={() => handleQuickCategoryCreate(index)}
                                                                >
                                                                    <Save className="h-3 w-3" /> Salvar Categoria
                                                                </Button>
                                                            </div>
                                                        </PopoverContent>
                                                    </Popover>
                                                </div>
                                                <Select value={item.category_id} onValueChange={(v) => updateItem(index, "category_id", v)}>
                                                    <SelectTrigger className="h-10 text-xs bg-background/50 border-border/50 rounded-xl"><SelectValue placeholder="Selecione ou clique [+] para criar" /></SelectTrigger>
                                                    <SelectContent>
                                                        {categories.filter(c => c.type === item.type).map((c) => (
                                                            <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>
                                                        ))}
                                                    </SelectContent>
                                                </Select>
                                            </div>

                                            <div className="space-y-1.5">
                                                <div className="flex items-center justify-between">
                                                    <Label className="text-[11px] text-muted-foreground uppercase font-black tracking-tighter">Meio de Pagamento</Label>
                                                    <Popover open={isCreatingCategory && newCategoryType === 'method'} onOpenChange={(o) => {
                                                        setIsCreatingCategory(o);
                                                        setNewCategoryType('method');
                                                    }}>
                                                        <PopoverTrigger asChild>
                                                            <button className="text-[10px] text-primary hover:underline flex items-center gap-1 font-bold">
                                                                <PlusCircle className="h-3 w-3" /> Criar novo
                                                            </button>
                                                        </PopoverTrigger>
                                                        <PopoverContent className="w-64 p-3 bg-card border-primary/20 shadow-xl" align="end">
                                                            <div className="space-y-2">
                                                                <p className="text-[10px] font-black uppercase text-primary">Novo Meio de Pagamento</p>
                                                                <Input
                                                                    placeholder="Ex: Cart├úo Mercado Pago"
                                                                    className="h-8 text-xs"
                                                                    value={newCategoryName}
                                                                    onChange={(e) => setNewCategoryName(e.target.value)}
                                                                    onKeyDown={(e) => e.key === 'Enter' && handleQuickCategoryCreate(index, 'method')}
                                                                    autoFocus
                                                                />
                                                                <Button
                                                                    className="w-full h-8 text-[10px] font-bold gap-2"
                                                                    size="sm"
                                                                    onClick={() => handleQuickCategoryCreate(index)}
                                                                >
                                                                    <Save className="h-3 w-3" /> Salvar Meio
                                                                </Button>
                                                            </div>
                                                        </PopoverContent>
                                                    </Popover>
                                                </div>
                                                <Select
                                                    value={item.payment_method_id || item.payment_method}
                                                    onValueChange={(v) => updateItem(index, "payment_method", v)}
                                                >
                                                    <SelectTrigger className="h-10 text-xs bg-background/50 border-border/50 rounded-xl"><SelectValue /></SelectTrigger>
                                                    <SelectContent>
                                                        {categories.filter(c => c.type === 'method').map((m) => (
                                                            <SelectItem key={m.id} value={m.id}>{m.name}</SelectItem>
                                                        ))}
                                                    </SelectContent>
                                                </Select>
                                            </div>

                                            <div className="space-y-1.5">
                                                <Label className="text-[11px] text-muted-foreground uppercase font-black tracking-tighter">Valor (R$) *</Label>
                                                <Input
                                                    type="number"
                                                    step="0.01"
                                                    placeholder="0,00"
                                                    value={item.amount}
                                                    className="h-12 text-lg font-mono font-bold bg-background text-primary border-primary/20 focus:border-primary focus:ring-4 focus:ring-primary/5 rounded-2xl"
                                                    onChange={(e) => updateItem(index, "amount", e.target.value)}
                                                />
                                            </div>

                                            <div className="space-y-1.5 flex flex-col justify-end">
                                                <Label className="text-[11px] text-muted-foreground uppercase font-black tracking-tighter">Comprovante / Anexo</Label>
                                                {item.receipt_url ? (
                                                    <div className="flex items-center justify-between p-2.5 bg-success/10 border border-success/30 rounded-2xl">
                                                        <div className="flex items-center gap-2">
                                                            <CheckCircle2 className="h-4 w-4 text-success" />
                                                            <span className="text-[11px] font-bold text-success/90">Anexado</span>
                                                        </div>
                                                        <div className="flex items-center gap-1">
                                                            <Button
                                                                variant="ghost"
                                                                size="icon"
                                                                className="h-8 w-8 text-success hover:bg-success/20"
                                                                onClick={() => window.open(item.receipt_url, '_blank')}
                                                            >
                                                                <Eye className="h-4 w-4" />
                                                            </Button>
                                                            <Button
                                                                variant="ghost"
                                                                size="icon"
                                                                className="h-8 w-8 text-destructive hover:bg-destructive/10"
                                                                onClick={() => updateItem(index, "receipt_url", "")}
                                                            >
                                                                <X className="h-4 w-4" />
                                                            </Button>
                                                        </div>
                                                    </div>
                                                ) : (
                                                    <div className="relative">
                                                        <input
                                                            type="file"
                                                            id={`receipt-${index}`}
                                                            className="hidden"
                                                            accept="image/*,application/pdf"
                                                            onChange={(e) => {
                                                                const file = e.target.files?.[0];
                                                                if (file) handleUpload(index, file);
                                                            }}
                                                        />
                                                        <Button
                                                            variant="outline"
                                                            className="w-full h-12 border-dashed border-2 bg-primary/5 border-primary/20 hover:bg-primary/10 transition-all rounded-2xl gap-2 text-xs font-black text-primary group"
                                                            asChild
                                                        >
                                                            <label htmlFor={`receipt-${index}`} className="cursor-pointer">
                                                                <Upload className="h-4 w-4 transition-transform group-hover:-translate-y-0.5" />
                                                                Upload
                                                            </label>
                                                        </Button>
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {currentStep === 4 && (
                        <div className="space-y-6 animate-in zoom-in-95 duration-300">
                            <div className="flex flex-col items-center text-center space-y-2 py-4">
                                <div className="h-16 w-16 rounded-[2rem] bg-success/10 border border-success/20 flex items-center justify-center mb-2 shadow-inner">
                                    <CheckCircle2 className="h-8 w-8 text-success" />
                                </div>
                                <h3 className="text-xl font-bold">Resumo Fiscal</h3>
                                <p className="text-muted-foreground text-xs uppercase font-black tracking-widest opacity-60">Confirme os valores do lote</p>
                            </div>

                            <Card className="bg-secondary/10 border-border/50 overflow-hidden rounded-[2.5rem] shadow-sm">
                                <div className="bg-secondary/20 p-6 border-b border-border/50">
                                    <div className="flex justify-between items-start">
                                        <div className="space-y-1">
                                            <p className="text-[10px] text-muted-foreground uppercase font-black tracking-widest">Identifica├º├úo</p>
                                            <p className="text-base font-bold text-foreground leading-tight">{form.description}</p>
                                        </div>
                                        <div className="text-right space-y-1">
                                            <p className="text-[10px] text-muted-foreground uppercase font-black tracking-widest">Compet├¬ncia</p>
                                            <p className="text-base font-bold text-foreground tabular-nums">{new Date(form.date + 'T12:00:00').toLocaleDateString('pt-BR')}</p>
                                        </div>
                                    </div>
                                </div>
                                <div className="p-6 space-y-6">
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="p-4 bg-success/5 rounded-3xl border border-success/10 shadow-sm">
                                            <div className="flex items-center gap-1.5 mb-1 text-success">
                                                <Plus className="h-3 w-3" />
                                                <p className="text-[9px] font-black uppercase tracking-widest">Entradas</p>
                                            </div>
                                            <p className="text-2xl font-black text-success tabular-nums tracking-tighter">{formatCurrency(totals.income)}</p>
                                        </div>
                                        <div className="p-4 bg-destructive/5 rounded-3xl border border-destructive/10 shadow-sm">
                                            <div className="flex items-center gap-1.5 mb-1 text-destructive">
                                                <Trash2 className="h-3 w-3" />
                                                <p className="text-[9px] font-black uppercase tracking-widest">Sa├¡das</p>
                                            </div>
                                            <p className="text-2xl font-black text-destructive tabular-nums tracking-tighter">{formatCurrency(totals.expense)}</p>
                                        </div>
                                    </div>

                                    <div className="flex items-center justify-between p-4 bg-background/50 rounded-2xl border border-border/30">
                                        <div className="space-y-0.5">
                                            <p className="text-[10px] font-black uppercase text-muted-foreground">Saldo L├¡quido</p>
                                            <p className="text-[9px] text-muted-foreground font-medium italic">Resultado deste lan├ºamento</p>
                                        </div>
