import { createContext, useContext, useState, useEffect, ReactNode, useMemo } from "react";
import { supabase } from "@/lib/supabase";
import type { User } from "@supabase/supabase-js";
import type { Database } from "@/types/database.types";
import { useQuery, useQueryClient } from "@tanstack/react-query";

type Profile = Database["public"]["Tables"]["profiles"]["Row"];
type Organization = Database["public"]["Tables"]["organizations"]["Row"];

interface ChurchSettings {
  churchName: string;
  displayName: string;
  cnpj: string;
  socialMedia: {
    instagram: string;
    facebook: string;
    youtube: string;
    whatsapp: string;
  };
}

interface ChurchContextType {
  user: User | null;
  profile: Profile | null;
  organization: Organization | null;
  settings: ChurchSettings;
  updateSettings: (s: Partial<ChurchSettings>) => Promise<void>;
  updateSocialMedia: (s: Partial<ChurchSettings["socialMedia"]>) => Promise<void>;
  hasSeenOnboarding: boolean;
  setHasSeenOnboarding: (v: boolean) => void;
  loading: boolean;
  logout: () => Promise<void>;
  // Role helpers
  isAdmin: boolean;
  isTreasurer: boolean;
  isSecretary: boolean;
  isLeader: boolean;
  isViewer: boolean;
  canManageFinances: boolean;
  canManageSecretariat: boolean;
  canAccessSecretariat: boolean;
  canWrite: boolean;
  refreshOrganization: () => Promise<void>;
}

const defaultSettings: ChurchSettings = {
  churchName: "Mordus Igreja",
  displayName: "Mordus",
  cnpj: "",
  socialMedia: { instagram: "", facebook: "", youtube: "", whatsapp: "" },
};

const ChurchContext = createContext<ChurchContextType | null>(null);

export function ChurchProvider({ children }: { children: ReactNode }) {
  const queryClient = useQueryClient();
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);

  const [hasSeenOnboarding, setHasSeenOnboarding] = useState(() => {
    return localStorage.getItem("onboarding-done") === "true";
  });

  useEffect(() => {
    localStorage.setItem("onboarding-done", String(hasSeenOnboarding));
  }, [hasSeenOnboarding]);

  // Auth Sync
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
      setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
      setAuthLoading(false);
      if (!session) {
        queryClient.clear();
      }
    });

    return () => subscription.unsubscribe();
  }, [queryClient]);

  // Profile Query
  const { data: profile, isLoading: profileLoading } = useQuery({
    queryKey: ["profile", user?.id],
    queryFn: async () => {
      if (!user?.id) return null;
      const { data, error } = await supabase
        .from("profiles")
        .select("*")
        .eq("id", user.id)
        .single();
      if (error) throw error;
      return data as Profile;
    },
    enabled: !!user?.id,
    staleTime: 1000 * 60 * 10, // 10 minutes
    retry: 1,
  });

  // Organization Query
  const { data: organization, isLoading: orgLoading } = useQuery({
    queryKey: ["organization", profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return null;
      const { data, error } = await supabase
        .from("organizations")
        .select("*")
        .eq("id", profile.organization_id)
        .single();
      if (error) throw error;
      return data as Organization;
    },
    enabled: !!profile?.organization_id,
    staleTime: 1000 * 60 * 10, // 10 minutes
    retry: 1,
  });

  const settings = useMemo(() => {
    if (!organization) return defaultSettings;
    return {
      churchName: organization.name,
      displayName: organization.name,
      cnpj: (organization as any).cnpj || "",
      socialMedia: {
        instagram: (organization as any).instagram || "",
        facebook: (organization as any).facebook || "",
        youtube: (organization as any).youtube || "",
        whatsapp: (organization as any).whatsapp || "",
      },
    };
  }, [organization]);

  const updateSettings = async (partial: Partial<ChurchSettings>) => {
    if (organization?.id) {
      const { error } = await supabase.from("organizations").update({
        name: partial.churchName || settings.churchName,
        cnpj: partial.cnpj || settings.cnpj,
      }).eq("id", organization.id);

      if (error) throw error;
      queryClient.invalidateQueries({ queryKey: ["organization"] });
    }
  };

  const updateSocialMedia = async (partial: Partial<ChurchSettings["socialMedia"]>) => {
    const newSocial = { ...settings.socialMedia, ...partial };
    if (organization?.id) {
      const { error } = await supabase.from("organizations").update({
        instagram: newSocial.instagram,
        facebook: newSocial.facebook,
        youtube: newSocial.youtube,
        whatsapp: newSocial.whatsapp
      }).eq("id", organization.id);

      if (error) throw error;
      queryClient.invalidateQueries({ queryKey: ["organization"] });
    }
  };

  const logout = async () => {
    await supabase.auth.signOut();
    queryClient.clear();
  };

  const isAdmin = profile?.role === "admin";
  const isTreasurer = profile?.role === "treasurer";
  const isSecretary = profile?.role === "secretary";
  const isLeader = profile?.role === "leader";
  const isViewer = profile?.role === "viewer";

  const canManageFinances = isAdmin || isTreasurer;
  const canManageSecretariat = isAdmin || isSecretary;
  const canAccessSecretariat = canManageSecretariat || isLeader;
  const canWrite = !isViewer;

  const loading = authLoading || (!!user && profileLoading);

  return (
    <ChurchContext.Provider value={{
      user, profile: profile || null, organization: organization || null, settings, updateSettings,
      updateSocialMedia, hasSeenOnboarding, setHasSeenOnboarding,
      loading, logout,
      isAdmin, isTreasurer, isSecretary, isLeader, isViewer,
      canManageFinances, canManageSecretariat, canAccessSecretariat, canWrite,
      refreshOrganization: async () => {
        await queryClient.invalidateQueries({ queryKey: ["profile"] });
        await queryClient.invalidateQueries({ queryKey: ["organization"] });
      }
    }}>
      {children}
    </ChurchContext.Provider>
  );
}

export function useChurch() {
  const ctx = useContext(ChurchContext);
  if (!ctx) throw new Error("useChurch must be used within ChurchProvider");
  return ctx;
}

import React, { createContext, useContext, useState, useCallback, ReactNode } from "react";
import { supabase } from "@/lib/supabase";
import { useChurch } from "@/contexts/ChurchContext";

interface Message {
    id: string;
    role: "user" | "assistant";
    content: string;
    timestamp: Date;
}

interface SidebarAlert {
    title: string;
    message: string;
    url?: string;
    active: boolean;
}

interface CopilotContextType {
    messages: Message[];
    sendMessage: (content: string) => Promise<void>;
    isLoading: boolean;
    sidebarAlert: SidebarAlert;
    triggerAlert: (title: string, message: string, url?: string) => void;
    clearAlert: () => void;
}

const CopilotContext = createContext<CopilotContextType | undefined>(undefined);

export function CopilotProvider({ children }: { children: ReactNode }) {
    const { profile, organization } = useChurch();
    const [messages, setMessages] = useState<Message[]>([
        {
            id: "1",
            role: "assistant",
            content: "Ol├í! Sou o Copilot do Mordus. Como posso ajudar com a Tesouraria ou Secretaria hoje?",
            timestamp: new Date(),
        },
    ]);
    const [isLoading, setIsLoading] = useState(false);
    const [sidebarAlert, setSidebarAlert] = useState<SidebarAlert>({
        title: "",
        message: "",
        active: false
    });

    const sendMessage = useCallback(async (content: string) => {
        if (!content.trim()) return;

        const userMessage: Message = {
            id: Date.now().toString(),
            role: "user",
            content,
            timestamp: new Date(),
        };

        setMessages((prev) => [...prev, userMessage]);
        setIsLoading(true);

        try {
            const { data, error } = await supabase.functions.invoke('mordus-copilot', {
                body: {
                    message: content,
                    context: {
                        user_role: profile?.role,
                        organization_name: organization?.name,
                        organization_id: organization?.id,
                        current_page: window.location.pathname,
                        history: messages.slice(-5).map(m => ({ role: m.role, content: m.content }))
                    }
                }
            });

            if (error) throw error;

            const assistantMessage: Message = {
                id: (Date.now() + 1).toString(),
                role: "assistant",
                content: data?.reply || "Desculpe, tive um problema ao processar sua solicita├º├úo.",
                timestamp: new Date(),
            };

            setMessages((prev) => [...prev, assistantMessage]);
        } catch (error) {
            console.error("Error sending message to Copilot:", error);
            const errorMessage: Message = {
                id: (Date.now() + 1).toString(),
                role: "assistant",
                content: "Ocorreu um erro ao conectar com a intelig├¬ncia artificial. Verifique sua conex├úo ou tente novamente mais tarde.",
                timestamp: new Date(),
            };
            setMessages((prev) => [...prev, errorMessage]);
        } finally {
            setIsLoading(false);
        }
    }, [profile, organization, messages]);

    const triggerAlert = useCallback((title: string, message: string, url?: string) => {
        setSidebarAlert({ title, message, url, active: true });
    }, []);

    const clearAlert = useCallback(() => {
        setSidebarAlert((prev) => ({ ...prev, active: false }));
    }, []);

    return (
        <CopilotContext.Provider value={{
            messages,
            sendMessage,
            isLoading,
            sidebarAlert,
            triggerAlert,
            clearAlert
        }}>
            {children}
        </CopilotContext.Provider>
    );
}

export function useCopilot() {
    const context = useContext(CopilotContext);
    if (context === undefined) {
        throw new Error("useCopilot must be used within a CopilotProvider");
    }
    return context;
}

import React, { createContext, useContext, useState, ReactNode } from "react";

interface TransactionModalContextType {
    isOpen: boolean;
    editingTransaction: any;
    openNewTransaction: () => void;
    openEditTransaction: (transaction: any) => void;
    closeTransactionModal: () => void;
}

const TransactionModalContext = createContext<TransactionModalContextType | undefined>(undefined);

export function TransactionModalProvider({ children }: { children: ReactNode }) {
    const [isOpen, setIsOpen] = useState(false);
    const [editingTransaction, setEditingTransaction] = useState<any>(null);

    const openNewTransaction = () => {
        setEditingTransaction(null);
        setIsOpen(true);
    };

    const openEditTransaction = (transaction: any) => {
        setEditingTransaction(transaction);
        setIsOpen(true);
    };

    const closeTransactionModal = () => {
        setIsOpen(false);
        setEditingTransaction(null);
    };

    return (
        <TransactionModalContext.Provider
            value={{
                isOpen,
                editingTransaction,
                openNewTransaction,
                openEditTransaction,
                closeTransactionModal,
            }}
        >
            {children}
        </TransactionModalContext.Provider>
    );
}

export function useTransactionModal() {
    const context = useContext(TransactionModalContext);
    if (context === undefined) {
        throw new Error("useTransactionModal must be used within a TransactionModalProvider");
    }
    return context;
}

import { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { GoogleDriveService } from '@/lib/googleDrive';
import { useChurch } from '@/contexts/ChurchContext';
import { toast } from 'sonner';

export function useGoogleDrive() {
    const { organization, refreshOrganization } = useChurch();
    const [service, setService] = useState<GoogleDriveService | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [accessToken, setAccessToken] = useState<string | null>(null);

    useEffect(() => {
        async function init() {
            const { data: { session } } = await supabase.auth.getSession();

            // O provider_token s├│ vem no login inicial via OAuth
            // Se n├úo houver, o usu├írio precisa "Conectar" novamente
            const token = session?.provider_token;

            if (token) {
                setAccessToken(token);
                setService(new GoogleDriveService(token));
            }
            setIsLoading(false);
        }

        init();
    }, []);

    const connect = async () => {
        const { error } = await supabase.auth.signInWithOAuth({
            provider: 'google',
            options: {
                queryParams: {
                    access_type: 'offline',
                },
                scopes: 'https://www.googleapis.com/auth/drive.file',
                redirectTo: window.location.origin + '/configuracoes',
            },
        });

        if (error) {
            toast.error('Erro ao conectar com Google Drive: ' + error.message);
        }
    };

    const saveRootFolder = async (folderId: string) => {
        if (!organization?.id) return;

        const { error } = await supabase
            .from('organizations')
            .update({ google_drive_folder_id: folderId } as any)
            .eq('id', organization.id);

        if (error) {
            toast.error('Erro ao salvar configura├º├úo da pasta');
            throw error;
        }

        await refreshOrganization();
        toast.success('Pasta do Drive vinculada com sucesso!');
    };

    return {
        service,
        isLoading,
        isConnected: !!accessToken,
        connect,
        saveRootFolder,
        currentFolderId: (organization as any)?.google_drive_folder_id,
    };
}

/**
 * Google Drive API Service
 * Handles folder creation, listing, and organization.
 */

export interface GoogleDriveFolder {
    id: string;
    name: string;
    mimeType: string;
}

export class GoogleDriveService {
    private accessToken: string;

    constructor(accessToken: string) {
        this.accessToken = accessToken;
    }

    private async fetchGoogleApi(endpoint: string, options: RequestInit = {}) {
        const response = await fetch(`https://www.googleapis.com/drive/v3${endpoint}`, {
            ...options,
            headers: {
                Authorization: `Bearer ${this.accessToken}`,
                'Content-Type': 'application/json',
                ...options.headers,
            },
        });

        if (!response.ok) {
            const error = await response.json();
            throw new Error(error.error?.message || 'Erro na API do Google Drive');
        }

        return response.json();
    }

    /**
     * Lista pastas dispon├¡veis no Drive
     */
    async listFolders(parentId?: string): Promise<GoogleDriveFolder[]> {
        const query = parentId
            ? `'${parentId}' in parents and mimeType = 'application/vnd.google-apps.folder' and trashed = false`
            : `mimeType = 'application/vnd.google-apps.folder' and trashed = false`;

        const data = await this.fetchGoogleApi(`/files?q=${encodeURIComponent(query)}&fields=files(id,name,mimeType)`);
        return data.files;
    }

    /**
     * Cria uma nova pasta
     */
    async createFolder(name: string, parentId?: string): Promise<GoogleDriveFolder> {
        const body: any = {
            name,
            mimeType: 'application/vnd.google-apps.folder',
        };

        if (parentId) {
            body.parents = [parentId];
        }

        return this.fetchGoogleApi('/files', {
            method: 'POST',
            body: JSON.stringify(body),
        });
    }

    /**
     * Verifica se uma pasta existe
     */
    async getFolder(folderId: string): Promise<GoogleDriveFolder | null> {
        try {
            return await this.fetchGoogleApi(`/files/${folderId}?fields=id,name,mimeType`);
        } catch (e) {
            return null;
        }
    }

    /**
     * Organiza arquivos (move um arquivo para uma pasta)
     */
    async moveFile(fileId: string, folderId: string) {
        // Primeiro pegamos os pais atuais
        const file = await this.fetchGoogleApi(`/files/${fileId}?fields=parents`);
        const previousParents = file.parents.join(',');

        return this.fetchGoogleApi(`/files/${fileId}?addParents=${folderId}&removeParents=${previousParents}`, {
            method: 'PATCH',
        });
    }
}

