import { useState, useEffect } from "react";
import { Plus, Pencil, Trash2, Loader2, Search } from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import { toast } from "sonner";
import { supabase } from "@/lib/supabase";
import { useChurch } from "@/contexts/ChurchContext";
import { Badge } from "@/components/ui/badge";
import type { Database } from "@/types/database.types";

type Category = Database["public"]["Tables"]["categories"]["Row"];

const emptyForm = { name: "", type: "income" };

const typeMap = {
  income: { label: "Entrada", color: "bg-emerald-500", text: "text-emerald-600", dot: "bg-emerald-500" },
  expense: { label: "Sa├¡da", color: "bg-rose-500", text: "text-rose-600", dot: "bg-rose-500" },
  method: { label: "Meio de Pagamento", color: "bg-sky-500", text: "text-sky-600", dot: "bg-sky-500" },
  occasion: { label: "Ocasi├úo / Evento", color: "bg-amber-500", text: "text-amber-600", dot: "bg-amber-500" },
};

export default function Categories() {
  const { organization } = useChurch();
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");

  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState(emptyForm);

  useEffect(() => {
    if (organization?.id) fetchCategories();
  }, [organization?.id]);

  const fetchCategories = async () => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from("categories")
        .select("*")
        .eq("organization_id", organization!.id)
        .neq("type", "church_role")
        .order("name");
      if (error) throw error;
      setCategories(data || []);
    } catch (err) {
      toast.error("Erro ao carregar classifica├º├Áes");
    } finally {
      setLoading(false);
    }
  };

  const openCreate = (type?: string) => {
    setEditingId(null);
    setForm({ ...emptyForm, type: (type as any) || "income" });
    setDialogOpen(true);
  };

  const openEdit = (c: Category) => {
    setEditingId(c.id);
    setForm({ name: c.name, type: (c.type as any) });
    setDialogOpen(true);
  };

  const handleSave = async () => {
    if (!form.name || !organization?.id) {
      toast.error("Preencha o nome da classifica├º├úo");
      return;
    }

    setIsSaving(true);
    try {
      const payload = {
        name: form.name.trim(),
        type: form.type,
        organization_id: organization.id,
      };

      if (editingId) {
        const { error } = await supabase.from("categories").update(payload).eq("id", editingId);
        if (error) throw error;
        toast.success("Classifica├º├úo atualizada");
      } else {
        const { error } = await supabase.from("categories").insert([payload]);
        if (error) throw error;
        toast.success("Classifica├º├úo criada");
      }

      setDialogOpen(false);
      fetchCategories();
    } catch (err) {
      toast.error("Erro ao salvar classifica├º├úo");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Deseja realmente excluir esta classifica├º├úo?")) return;
    try {
      const { error } = await supabase.from("categories").delete().eq("id", id);
      if (error) throw error;
      toast.success("Classifica├º├úo removida");
      setCategories(prev => prev.filter(c => c.id !== id));
    } catch (err: any) {
      console.error(err);
      toast.error("N├úo foi poss├¡vel excluir. Verifique se existem lan├ºamentos vinculados.");
    }
  };

  const filteredCategories = categories.filter(c =>
    c.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const categoriesByType = {
    income: filteredCategories.filter(c => c.type === "income"),
    expense: filteredCategories.filter(c => c.type === "expense"),
    method: filteredCategories.filter(c => c.type === "method"),
    occasion: filteredCategories.filter(c => c.type === "occasion"),
  };

  if (!organization) return null;

  return (
    <div className="animate-fade-in max-w-[1600px] mx-auto space-y-6 pb-10">
      {/* Header section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-1">
        <div className="space-y-1">
          <h1 className="text-2xl font-bold tracking-tight">Classifica├º├Áes</h1>
          <p className="text-muted-foreground text-sm">Organize suas entradas, sa├¡das e eventos em colunas.</p>
        </div>

        <div className="flex items-center gap-3">
          <div className="relative w-full md:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Buscar classifica├º├úo..."
              className="pl-9 h-10 bg-background/50 border-border/50 focus-visible:ring-primary/20"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
          <Button onClick={() => openCreate()} size="sm" className="h-10 px-4 gap-2">
            <Plus className="h-4 w-4" />
            Novo Registro
          </Button>
        </div>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-20 gap-4">
          <Loader2 className="h-10 w-10 animate-spin text-primary/40" />
          <p className="text-sm text-muted-foreground">Carregando classifica├º├Áes...</p>
        </div>
      ) : (
        <ScrollArea className="w-full whitespace-nowrap pb-6">
          <div className="flex gap-4 min-w-full lg:min-w-0">
            {Object.entries(categoriesByType).map(([type, items]) => {
              const info = typeMap[type as keyof typeof typeMap];
              return (
                <div key={type} className="flex-1 min-w-[300px] max-w-[400px] flex flex-col gap-3">
                  {/* Column Header */}
                  <div className="flex items-center justify-between bg-card/40 border border-border/50 p-3 rounded-xl backdrop-blur-sm">
                    <div className="flex items-center gap-2">
                      <div className={`h-2.5 w-2.5 rounded-full ${info.dot}`} />
                      <h2 className="text-sm font-bold uppercase tracking-wide text-foreground/80">{info.label}s</h2>
                    </div>
                    <Badge variant="secondary" className="bg-secondary/50 text-[10px] h-4.5 font-bold">
                      {items.length}
                    </Badge>
                  </div>

                  {/* Column Content */}
                  <div className="flex flex-col gap-2 min-h-[500px] bg-secondary/5 border border-border/40 rounded-2xl p-2">
                    {items.map((cat) => (
                      <Card key={cat.id} className="group hover:shadow-md hover:border-primary/20 transition-all border-border/50 bg-card relative overflow-hidden shrink-0">
                        <div className={`absolute left-0 top-0 bottom-0 w-1 ${info.dot} opacity-40`} />
                        <CardContent className="p-3 py-4 flex items-center justify-between">
                          <span className="font-medium text-[14px] truncate flex-1 pr-2">{cat.name}</span>
                          <div className="flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-all">
                            <Button variant="ghost" size="icon" className="h-7 w-7 text-muted-foreground hover:text-foreground" onClick={() => openEdit(cat)}>
                              <Pencil className="h-3 w-3" />
                            </Button>
                            <Button variant="ghost" size="icon" className="h-7 w-7 text-muted-foreground hover:text-destructive" onClick={() => handleDelete(cat.id)}>
                              <Trash2 className="h-3 w-3" />
                            </Button>
                          </div>
                        </CardContent>
                      </Card>
                    ))}

                    <Button
                      variant="ghost"
                      className="w-full h-12 border border-dashed border-border/40 hover:border-primary/30 hover:bg-primary/5 text-muted-foreground hover:text-primary transition-all rounded-xl gap-2 mt-auto"
                      onClick={() => openCreate(type)}
                    >
                      <Plus className="h-4 w-4" />
                      Adicionar item
                    </Button>
                  </div>
                </div>
              );
            })}
          </div>
          <ScrollBar orientation="horizontal" />
        </ScrollArea>
      )}

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="sm:max-w-[425px]">
          <DialogHeader>
            <DialogTitle className="text-xl font-bold">{editingId ? "Editar Classifica├º├úo" : "Nova Classifica├º├úo"}</DialogTitle>
            <p className="text-sm text-muted-foreground">Defina o nome e o tipo desta classifica├º├úo.</p>
          </DialogHeader>

          <div className="space-y-5 py-6">
            <div className="space-y-2">
              <Label className="text-sm font-semibold">Nome</Label>
              <Input
                placeholder="Ex: Oferta de Miss├Áes, Aluguel..."
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                className="h-12 text-base"
                autoFocus
              />
            </div>

            <div className="space-y-2">
              <Label className="text-sm font-semibold">Tipo</Label>
              <Select value={form.type} onValueChange={(v) => setForm({ ...form, type: v as any })}>
                <SelectTrigger className="h-12 text-base">
                  <SelectValue placeholder="Selecione" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="income">Entrada (Receita)</SelectItem>
                  <SelectItem value="expense">Sa├¡da (Despesa)</SelectItem>
                  <SelectItem value="method">Meio de Pagamento</SelectItem>
                  <SelectItem value="occasion">Ocasi├úo (Evento, Reuni├úo)</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>

          <DialogFooter className="gap-2 sm:gap-0">
            <Button variant="outline" onClick={() => setDialogOpen(false)} className="flex-1 sm:flex-none">Cancelar</Button>
            <Button disabled={isSaving} onClick={handleSave} className="flex-1 sm:flex-none">
              {isSaving ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : editingId ? "Salvar" : "Adicionar"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Lock, Unlock, Eye, ChevronDown, ChevronUp, Loader2, ArrowRight, Trash2, Calendar, Wallet, AlertTriangle } from "lucide-react";
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table";
import { Skeleton } from "@/components/ui/skeleton";
import { ScrollArea } from "@/components/ui/scroll-area";
import { supabase } from "@/lib/supabase";
import { useChurch } from "@/contexts/ChurchContext";
import { toast } from "sonner";
import type { Database } from "@/types/database.types";

const months = [
  { value: "01", label: "Janeiro" }, { value: "02", label: "Fevereiro" }, { value: "03", label: "Mar├ºo" },
  { value: "04", label: "Abril" }, { value: "05", label: "Maio" }, { value: "06", label: "Junho" },
  { value: "07", label: "Julho" }, { value: "08", label: "Agosto" }, { value: "09", label: "Setembro" },
  { value: "10", label: "Outubro" }, { value: "11", label: "Novembro" }, { value: "12", label: "Dezembro" },
];

const currentYearConst = new Date().getFullYear();
const years = Array.from({ length: 3 }, (_, i) => String(currentYearConst - 1 + i));

type Closure = Database["public"]["Tables"]["monthly_closures"]["Row"];
type Transaction = Database["public"]["Tables"]["transactions"]["Row"] & { categories?: { name: string } | null };

function formatCurrency(value: number) {
  return value.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}

function formatDate(dateStr: string) {
  return new Date(dateStr + "T12:00:00").toLocaleDateString("pt-BR");
}

export default function Closures() {
  const { organization, profile } = useChurch();
  const [closures, setClosures] = useState<Closure[]>([]);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [expandedTxs, setExpandedTxs] = useState<Record<string, Transaction[]>>({});
  const [loading, setLoading] = useState(true);
  const [isClosingId, setIsClosingId] = useState<string | null>(null);

  // States for period selection
  const currentMonth = new Date().getMonth() + 1;
  const currentYear = new Date().getFullYear();
  const [selectedMonth, setSelectedMonth] = useState(String(currentMonth).padStart(2, "0"));
  const [selectedYear, setSelectedYear] = useState(String(currentYear));
  const [lastClosure, setLastClosure] = useState<Closure | null>(null);
  const [hasRetroactiveUnclosed, setHasRetroactiveUnclosed] = useState(false);

  const [currentPeriodStats, setCurrentPeriodStats] = useState({
    income: 0,
    expense: 0,
    count: 0,
    initial: 0,
    start: "",
    end: "",
    error: null as string | null
  });

  useEffect(() => {
    if (organization?.id) {
      fetchClosuresAndLast();
    }
  }, [organization?.id]);

  useEffect(() => {
    if (organization?.id && (lastClosure !== undefined)) {
      fetchCurrentMonthStats();
    }
  }, [organization?.id, selectedMonth, selectedYear, lastClosure]);

  const fetchClosuresAndLast = async () => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from("monthly_closures")
        .select("*")
        .eq("organization_id", organization!.id)
        .order("end_date", { ascending: false });

      if (error) throw error;
      setClosures(data || []);
      const last = data && data.length > 0 ? data[0] : null;
      setLastClosure(last);

      const isFlexible = (organization as any)?.closure_mode === 'flexible';

      if (data && data.length > 0 && !isFlexible) {
        const oldestClosure = data[data.length - 1];
        const { count } = await supabase
          .from("transactions")
          .select("*", { count: 'exact', head: true })
          .eq("organization_id", organization!.id)
          .lt("date", oldestClosure.start_date);
        setHasRetroactiveUnclosed((count || 0) > 0);
      } else {
        setHasRetroactiveUnclosed(false);
      }
    } catch (err) {
      toast.error("Erro ao carregar hist├│ricos");
    } finally {
      setLoading(false);
    }
  };

  const fetchCurrentMonthStats = async () => {
    // Calculamos o primeiro dia do m├¬s que o usu├írio selecionou
    const targetStartDateStr = `${selectedYear}-${selectedMonth}-01`;
    const targetStartDate = new Date(targetStartDateStr + "T12:00:00");

    // Buscamos se existe algum fechamento que termina ANTES desse m├¬s selecionado
    // Como closures est├í ordenado por end_date desc, vamos filtrar
    const previousClosures = closures.filter(c => new Date(c.end_date) < targetStartDate);
    const immediatePrevious = previousClosures.length > 0 ? previousClosures[0] : null;

    const isFlexible = (organization as any)?.closure_mode === 'flexible';
    let startDateStr = "";

    if (isFlexible) {
      // Modo Flex├¡vel: O in├¡cio ├® sempre o dia 1 do m├¬s selecionado
      startDateStr = targetStartDateStr;
    } else if (immediatePrevious) {
      // Modo Cont├¡nuo: O in├¡cio ├® o dia seguinte ao ├║ltimo fechamento
      const lastEnd = new Date(immediatePrevious.end_date + "T12:00:00");
      lastEnd.setDate(lastEnd.getDate() + 1);
      startDateStr = lastEnd.toISOString().split('T')[0];
    } else {
      // Se n├úo h├í nenhum fechamento ANTES deste m├¬s, buscamos desde o in├¡cio dos tempos
      startDateStr = "2020-01-01";
    }

    // O fim ├® sempre o ├║ltimo dia do m├¬s selecionado
    const lastDay = new Date(Number(selectedYear), Number(selectedMonth), 0);
    const endDateStr = lastDay.getFullYear() + '-' + String(lastDay.getMonth() + 1).padStart(2, '0') + '-' + String(lastDay.getDate()).padStart(2, '0');

    // O saldo inicial deste per├¡odo deve vir do ├║ltimo fechamento ANTES dele
    const initialBalance = immediatePrevious?.final_balance || 0;

    // Prote├º├úo: Verificar se este m├¬s (especificamente este range) j├í est├í coberto por algum fechamento
    const alreadyClosed = closures.find(c => c.end_date === endDateStr);

    if (alreadyClosed) {
      setCurrentPeriodStats({
        income: 0,
        expense: 0,
        count: 0,
        initial: 0,
        start: alreadyClosed.start_date,
        end: alreadyClosed.end_date,
        error: `Este per├¡odo (${months.find(m => m.value === selectedMonth)?.label}/${selectedYear}) j├í foi fechado.`
      });
      return;
    }

    try {
      const { data, error } = await supabase
        .from("transactions")
        .select("amount, type, status")
        .eq("organization_id", organization!.id)
        .gte("date", startDateStr)
        .lte("date", endDateStr);

      if (error) throw error;

      const stats = {
        income: 0,
        expense: 0,
        count: data?.length || 0,
        initial: initialBalance,
        start: startDateStr,
        end: endDateStr,
        error: null as string | null
      };

      data?.forEach(tx => {
        // REGRA DE CAIXA: Apenas itens 'completed' (pagos) entram no fechamento
        if (tx.status === 'completed' || !tx.status) {
          if (tx.type === "income") {
            stats.income += tx.amount;
          } else {
            stats.expense += tx.amount;
          }
        }
      });
      setCurrentPeriodStats(stats);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchTransactionsForClosure = async (closure: Closure) => {
    if (expandedTxs[closure.id]) return;
    try {
      const { data, error } = await supabase
        .from("transactions")
        .select(`*, categories!category_id(name)`)
        .eq("organization_id", organization!.id)
        .gte("date", closure.start_date)
        .lte("date", closure.end_date)
        .order("date");
      if (error) throw error;
      setExpandedTxs(prev => ({ ...prev, [closure.id]: (data as any) || [] }));
    } catch (err) {
      toast.error("Erro ao carregar transa├º├Áes do per├¡odo");
    }
  };

  const handleClosePeriod = async () => {
    setIsClosingId("current");
    try {
      const finalBalance = currentPeriodStats.initial + currentPeriodStats.income - currentPeriodStats.expense;

      const { error } = await supabase.from("monthly_closures").insert([{
        organization_id: organization!.id,
        start_date: currentPeriodStats.start,
        end_date: currentPeriodStats.end,
        initial_balance: currentPeriodStats.initial,
        total_income: currentPeriodStats.income,
        total_expense: currentPeriodStats.expense,
        final_balance: finalBalance,
        status: 'closed',
        closed_by: profile?.id,
        closed_at: new Date().toISOString()
      }]);

      if (error) throw error;
      toast.success("M├¬s fechado com sucesso!");
      fetchClosuresAndLast();
    } catch (err) {
      toast.error("Erro ao realizar fechamento");
    } finally {
      setIsClosingId(null);
    }
  };

  const handleDeleteClosure = async (id: string) => {
    if (!confirm("Tem certeza que deseja excluir este fechamento? O per├¡odo voltar├í a ficar em aberto para altera├º├Áes. Recomenda-se excluir apenas o fechamento mais recente para manter a integridade dos saldos transportados.")) return;

    try {
      const { error } = await supabase.from("monthly_closures").delete().eq("id", id);
      if (error) throw error;
      toast.success("Fechamento removido com sucesso!");
      fetchClosuresAndLast(); // Refresh to update lastClosure
    } catch (err) {
      toast.error("Erro ao excluir fechamento");
    }
  };

  if (!organization) return <div className="p-8 text-center text-muted-foreground font-mono">Carregando...</div>;

  const saldoProjetado = currentPeriodStats.initial + currentPeriodStats.income - currentPeriodStats.expense;
  const isDifferentMonth = (selectedMonth !== String(currentMonth).padStart(2, "0")) || (selectedYear !== String(currentYear));

  return (
    <div className="animate-fade-in space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div>
          <div className="flex items-center gap-2">
            <h2 className="text-lg font-semibold text-foreground">Fechamento de Caixa</h2>
            <Badge variant="outline" className="text-[9px] font-black uppercase tracking-widest bg-secondary/30 border-primary/20">
              Modo {(organization as any)?.closure_mode === 'flexible' ? 'Flex├¡vel' : 'Cont├¡nuo'}
            </Badge>
          </div>
          <p className="text-muted-foreground text-[12px] mt-1">Audit trail e encerramento de per├¡odos ÔÇö {organization.name}</p>
        </div>

        <div className="flex items-center gap-2 bg-secondary/20 p-1.5 rounded-lg border border-border/50">
          <Calendar className="h-4 w-4 text-muted-foreground ml-1 mr-1" />
          <Select value={selectedMonth} onValueChange={setSelectedMonth}>
            <SelectTrigger className="h-8 w-32 text-xs bg-background"><SelectValue /></SelectTrigger>
            <SelectContent>
              {months.map(m => <SelectItem key={m.value} value={m.value}>{m.label}</SelectItem>)}
            </SelectContent>
          </Select>
          <Select value={selectedYear} onValueChange={setSelectedYear}>
            <SelectTrigger className="h-8 w-24 text-xs bg-background"><SelectValue /></SelectTrigger>
            <SelectContent>
              {years.map(y => <SelectItem key={y} value={y}>{y}</SelectItem>)}
            </SelectContent>
          </Select>
        </div>
      </div>

      {hasRetroactiveUnclosed && (
        <Card className="bg-destructive/5 border-destructive/20 border-l-4 border-l-destructive shadow-none">
          <CardContent className="p-4 flex items-center gap-4">
            <div className="h-10 w-10 rounded-full bg-destructive/10 flex items-center justify-center flex-shrink-0">
              <AlertTriangle className="h-5 w-5 text-destructive" />
            </div>
            <div className="flex-1">
              <div className="flex items-center gap-2">
                <h4 className="text-sm font-bold text-destructive">Lan├ºamentos Retroativos Detectados</h4>
                <Badge variant="outline" className="bg-destructive/10 text-destructive border-destructive/20 text-[9px] uppercase font-black">Aten├º├úo</Badge>
              </div>
              <p className="text-[11px] text-muted-foreground mt-0.5 leading-relaxed">
                Existem transa├º├Áes datadas <strong>antes</strong> do seu primeiro fechamento registrado que n├úo foram inclu├¡das em nenhum per├¡odo.
                Isso causa inconsist├¬ncia no saldo inicial. Recomendamos excluir os fechamentos atuais e refaz├¬-los a partir do m├¬s desta transa├º├úo.
              </p>
            </div>
          </CardContent>
        </Card>
      )}

      <Card className={`bg-card border-border border-l-4 ${isDifferentMonth ? 'border-l-orange-500/40' : 'border-l-primary/40'}`}>
        <CardHeader className="py-4 flex flex-row items-center justify-between space-y-0">
          <div className="flex items-center gap-3">
            <Unlock className={`h-4 w-4 ${isDifferentMonth ? 'text-orange-500' : 'text-primary'}`} />
            <div>
              <CardTitle className="text-sm font-semibold">
                Per├¡odo em Aberto {isDifferentMonth && <span className="text-orange-500 ml-1 text-[10px] uppercase font-black">(Sele├º├úo)</span>}
              </CardTitle>
              {currentPeriodStats.start && (
                <p className="text-[11px] text-muted-foreground font-mono mt-0.5">
                  {formatDate(currentPeriodStats.start)} <ArrowRight className="h-3 w-3 inline mx-1 opacity-40" /> {formatDate(currentPeriodStats.end)}
                </p>
              )}
            </div>
          </div>
          <Badge variant="secondary" className={`${isDifferentMonth ? 'bg-orange-500/15 text-orange-600' : 'bg-success/15 text-success'} border-0 text-[10px]`}>
            {isDifferentMonth ? 'Revisando Per├¡odo' : 'Aguardando Fechamento'}
          </Badge>
        </CardHeader>
        <CardContent className="pb-4 pt-2">
          <div className="grid grid-cols-2 md:grid-cols-5 gap-6">
            <div>
              <p className="text-[10px] text-muted-foreground uppercase font-bold flex items-center gap-1"><Wallet className="h-3 w-3" /> Saldo Anterior</p>
              {loading ? <Skeleton className="h-6 w-24" /> : <p className="text-lg font-bold font-mono text-muted-foreground">{formatCurrency(currentPeriodStats.initial)}</p>}
            </div>
            <div>
              <p className="text-[10px] text-muted-foreground uppercase font-bold">Entradas</p>
              {loading ? <Skeleton className="h-6 w-24" /> : <p className="text-lg font-bold font-mono text-success">{formatCurrency(currentPeriodStats.income)}</p>}
            </div>
            <div>
              <p className="text-[10px] text-muted-foreground uppercase font-bold">Sa├¡das</p>
              {loading ? <Skeleton className="h-6 w-24" /> : <p className="text-lg font-bold font-mono text-destructive">{formatCurrency(currentPeriodStats.expense)}</p>}
            </div>
            <div>
              <p className="text-[10px] text-primary uppercase font-bold">Saldo Projetado</p>
              {loading ? <Skeleton className="h-6 w-24" /> : <p className={`text-lg font-bold font-mono ${saldoProjetado >= 0 ? 'text-primary' : 'text-destructive'}`}>{formatCurrency(saldoProjetado)}</p>}
            </div>
            <div className="flex flex-col justify-end">
              <Button size="sm" className="bg-primary hover:bg-primary/90 text-primary-foreground font-semibold rounded-full px-6" onClick={handleClosePeriod} disabled={isClosingId === "current" || currentPeriodStats.error !== null || (currentPeriodStats.count === 0 && currentPeriodStats.initial === 0)}>
                {isClosingId === "current" ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Lock className="h-3.5 w-3.5 mr-2" />}
                Finalizar M├¬s
              </Button>
            </div>
          </div>

          {currentPeriodStats.error && (
            <div className="mt-4 p-2 bg-destructive/10 border border-destructive/20 rounded-md text-[10px] text-destructive flex items-center gap-2 animate-in fade-in slide-in-from-top-1 duration-300">
              <AlertTriangle className="h-3.5 w-3.5" />
              {currentPeriodStats.error}
            </div>
          )}

          {!currentPeriodStats.error && lastClosure && currentPeriodStats.start && new Date(currentPeriodStats.start) > new Date(lastClosure.end_date) && (
            <div className="mt-4 p-2 bg-secondary/10 border border-border rounded-md text-[10px] text-muted-foreground flex items-center gap-2 italic">
              <span className="h-1.5 w-1.5 rounded-full bg-primary animate-pulse" />
              Este fechamento iniciar├í exatamente onde o ├║ltimo parou ({formatDate(lastClosure.end_date)}).
            </div>
          )}
        </CardContent>
      </Card>

      <div className="pt-4">
        <h3 className="text-[12px] font-black text-muted-foreground uppercase tracking-widest mb-4 flex items-center gap-2">
          <div className="h-1 w-1 rounded-full bg-primary" /> Hist├│rico de Fechamentos
        </h3>

        <Card className="bg-card border-border shadow-sm overflow-hidden w-full">
          <ScrollArea className="h-[calc(100vh-500px)] w-full">
            <Table className="border-collapse border border-border/50">
              <TableHeader className="sticky top-0 bg-secondary/20 backdrop-blur-sm z-10 border-b border-border">
                <TableRow className="hover:bg-transparent">
                  <TableHead className="w-[4%] text-[10px]"></TableHead>
                  <TableHead className="text-[11px] font-black text-muted-foreground text-center border-r border-border/50">Per├¡odo</TableHead>
                  <TableHead className="text-[11px] font-black text-muted-foreground text-center border-r border-border/50">S. Anterior</TableHead>
                  <TableHead className="text-[11px] font-black text-muted-foreground text-center border-r border-border/50">Entradas</TableHead>
                  <TableHead className="text-[11px] font-black text-muted-foreground text-center border-r border-border/50">Sa├¡das</TableHead>
                  <TableHead className="text-[11px] font-black text-muted-foreground text-center border-r border-border/50">Saldo Final</TableHead>
                  <TableHead className="text-[11px] font-black text-muted-foreground text-center">A├º├Áes</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                  Array.from({ length: 5 }).map((_, i) => (
                    <TableRow key={i}>
                      <TableCell colSpan={7}><Skeleton className="h-6 w-full" /></TableCell>
                    </TableRow>
                  ))
                ) : (
                  <>
                    {closures.map((closure) => (
                      <React.Fragment key={closure.id}>
                        <TableRow
                          className="group transition-colors odd:bg-transparent even:bg-secondary/10 hover:bg-secondary/20 border-b border-border/50 cursor-pointer"
                          onClick={() => {
                            const nextId = expandedId === closure.id ? null : closure.id;
                            setExpandedId(nextId);
                            if (nextId) fetchTransactionsForClosure(closure);
                          }}
                        >
                          <TableCell className="border-r border-border/50 text-center">
                            {expandedId === closure.id ? <ChevronUp className="h-3 w-3 mx-auto text-primary" /> : <ChevronDown className="h-3 w-3 mx-auto text-muted-foreground" />}
                          </TableCell>
                          <TableCell className="border-r border-border/50 text-center py-2">
                            <span className="text-[13px] font-black text-foreground">
                              {formatDate(closure.start_date)} <ArrowRight className="h-2 w-2 inline mx-1 opacity-40" /> {formatDate(closure.end_date)}
                            </span>
                          </TableCell>
                          <TableCell className="border-r border-border/50 text-center py-2 font-mono tabular-nums text-[13px] text-muted-foreground">
                            {formatCurrency(Number(closure.initial_balance || 0))}
                          </TableCell>
                          <TableCell className="border-r border-border/50 text-center py-2 font-mono tabular-nums text-[13px] text-success font-bold">
                            {formatCurrency(Number(closure.total_income || 0))}
                          </TableCell>
                          <TableCell className="border-r border-border/50 text-center py-2 font-mono tabular-nums text-[13px] text-destructive font-bold">
                            {formatCurrency(Number(closure.total_expense || 0))}
                          </TableCell>
                          <TableCell className="border-r border-border/50 text-center py-2 font-mono tabular-nums text-[13px] font-black text-foreground">
                            {formatCurrency(Number(closure.final_balance || 0))}
                          </TableCell>
                          <TableCell className="py-2 text-center">
                            <div className="flex items-center justify-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                              <button onClick={(e) => { e.stopPropagation(); handleDeleteClosure(closure.id); }} className="p-1 px-1.5 rounded-md hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-colors"><Trash2 className="h-3 w-3" /></button>
                            </div>
                          </TableCell>
                        </TableRow>
                        {expandedId === closure.id && (
                          <TableRow className="bg-secondary/5">
                            <TableCell colSpan={7} className="p-0 border-b border-border">
                              <div className="p-4 animate-in slide-in-from-top-2 duration-300">
                                <div className="rounded-lg border border-border/50 overflow-hidden shadow-sm">
                                  <Table className="border-collapse">
                                    <TableHeader className="bg-secondary/20">
                                      <TableRow className="hover:bg-transparent">
                                        <TableHead className="text-[10px] font-black text-muted-foreground border-r border-border/50 text-center">DATA</TableHead>
                                        <TableHead className="text-[10px] font-black text-muted-foreground border-r border-border/50 text-center">DESCRI├ç├âO</TableHead>
                                        <TableHead className="text-[10px] font-black text-muted-foreground border-r border-border/50 text-center">CATEGORIA</TableHead>
                                        <TableHead className="text-[10px] font-black text-muted-foreground text-center">VALOR</TableHead>
                                      </TableRow>
                                    </TableHeader>
                                    <TableBody>
                                      {!expandedTxs[closure.id] ? (
                                        Array.from({ length: 3 }).map((_, i) => (
                                          <TableRow key={i}><TableCell colSpan={4}><Skeleton className="h-5 w-full" /></TableCell></TableRow>
                                        ))
                                      ) : expandedTxs[closure.id].length === 0 ? (
                                        <TableRow><TableCell colSpan={4} className="text-center py-8 text-xs italic text-muted-foreground">Sem transa├º├Áes no per├¡odo</TableCell></TableRow>
                                      ) : expandedTxs[closure.id].map((tx) => (
                                        <TableRow key={tx.id} className="hover:bg-secondary/10 transition-colors border-b border-border/50">
                                          <TableCell className="text-[11px] font-mono border-r border-border/50 text-center">{formatDate(tx.date)}</TableCell>
                                          <TableCell className="text-[12px] font-bold border-r border-border/50 text-center">{tx.description}</TableCell>
                                          <TableCell className="border-r border-border/50 text-center">
                                            <Badge variant="outline" className="text-[9px] border-border/50 h-4 px-1.5 font-medium">{tx.categories?.name || "Geral"}</Badge>
                                          </TableCell>
                                          <TableCell className={`text-[12px] text-center font-bold font-mono ${tx.type === "income" ? "text-success" : "text-destructive"}`}>
                                            {tx.type === "income" ? "+" : "-"}{formatCurrency(tx.amount)}
                                          </TableCell>
                                        </TableRow>
                                      ))}
                                    </TableBody>
                                  </Table>
                                </div>
                              </div>
                            </TableCell>
                          </TableRow>
                        )}
                      </React.Fragment>
                    ))}
                    {!loading && closures.length === 0 && (
                      <TableRow><TableCell colSpan={7} className="text-center py-20 text-muted-foreground italic border-b border-border/50">Nenhum fechamento registrado</TableCell></TableRow>
                    )}
                  </>
                )}
              </TableBody>
            </Table>
          </ScrollArea>
        </Card>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Plus, MapPin, Pencil, Trash2, Loader2, Users, Search, ChevronDown, ChevronUp, Type, User } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import { toast } from "sonner";
import { supabase } from "@/lib/supabase";
import { useChurch } from "@/contexts/ChurchContext";
import { TableToolbar } from "@/components/TableToolbar";
import type { Database } from "@/types/database.types";

type Congregation = Database["public"]["Tables"]["congregations"]["Row"];

const emptyForm = { name: "", address: "", responsible_name: "", member_count: "" };

export default function Congregacoes() {
  const { organization } = useChurch();
  const [items, setItems] = useState<Congregation[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState(emptyForm);

  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [congregationMembers, setCongregationMembers] = useState<Record<string, any[]>>({});
  const [membersLoading, setMembersLoading] = useState<Record<string, boolean>>({});

  const [sortField, setSortField] = useState("name");
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>("asc");
  const [visibleColumns, setVisibleColumns] = useState<string[]>(["name", "responsible", "address", "members"]);

  useEffect(() => {
    if (organization?.id) fetchCongregations();
  }, [organization?.id, sortField, sortOrder]);

  const fetchCongregations = async () => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from("congregations")
        .select(`
          *,
          members:members(count)
        `)
        .eq("organization_id", organization!.id)
        .order(sortField, { ascending: sortOrder === 'asc' });
      if (error) throw error;

      const congregationsWithCount = (data || []).map(c => ({
        ...c,
        real_member_count: (c as any).members?.[0]?.count || 0
      }));
      setItems(congregationsWithCount);
    } catch (err) {
      toast.error("Erro ao carregar congrega├º├Áes");
    } finally {
      setLoading(false);
    }
  };

  const fetchMembersForCongregation = async (congId: string) => {
    if (congregationMembers[congId]) return;
    try {
      setMembersLoading(prev => ({ ...prev, [congId]: true }));
      const { data, error } = await supabase
        .from("members")
        .select("*")
        .eq("congregation_id", congId)
        .order("full_name");
      if (error) throw error;
      setCongregationMembers(prev => ({ ...prev, [congId]: data || [] }));
    } catch (err) {
      toast.error("Erro ao carregar membros");
    } finally {
      setMembersLoading(prev => ({ ...prev, [congId]: false }));
    }
  };

  const handleToggleExpand = (congId: string) => {
    const isExpanding = expandedId !== congId;
    setExpandedId(isExpanding ? congId : null);
    if (isExpanding) {
      fetchMembersForCongregation(congId);
    }
  };

  const openCreate = () => { setEditingId(null); setForm(emptyForm); setDialogOpen(true); };
  const openEdit = (c: Congregation) => {
    setEditingId(c.id);
    setForm({
