const monthNames = ["Jan", "Fev", "Mar", "Abr", "Mai", "Jun", "Jul", "Ago", "Set", "Out", "Nov", "Dez"];

const formatYAxis = (v: number) => {
  if (v === 0) return "0";
  if (v < 1000) return v.toString();
  return `${(v / 1000).toFixed(1)}k`;
};

const Counter = ({ value, prefix = "", suffix = "", decimals = 0 }: { value: number, prefix?: string, suffix?: string, decimals?: number }) => {
  const [displayValue, setDisplayValue] = useState(0);
  const previousValue = useRef(0);

  useEffect(() => {
    let startTimestamp: number | null = null;
    const duration = 800; // 0.8 seconds
    const startValue = previousValue.current;
    const endValue = value;

    const step = (timestamp: number) => {
      if (!startTimestamp) startTimestamp = timestamp;
      const progress = Math.min((timestamp - startTimestamp) / duration, 1);
      const easeOutQuad = (t: number) => t * (2 - t);
      const current = easeOutQuad(progress) * (endValue - startValue) + startValue;

      setDisplayValue(current);
      if (progress < 1) {
        window.requestAnimationFrame(step);
      } else {
        previousValue.current = endValue;
      }
    };

    const animFrame = window.requestAnimationFrame(step);
    return () => window.cancelAnimationFrame(animFrame);
  }, [value]);

  return (
    <span>
      {prefix}
      {displayValue.toLocaleString("pt-BR", {
        minimumFractionDigits: decimals,
        maximumFractionDigits: decimals
      })}
      {suffix}
    </span>
  );
};

export default function Dashboard() {
  const { organization, canManageFinances } = useChurch();
  const queryClient = useQueryClient();
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [month, setMonth] = useState("all");
  const [showExpenses, setShowExpenses] = useState(() => {
    return localStorage.getItem("dashboard-show-expenses") === "true";
  });
  const [searchParams] = useSearchParams();
  const activeTab = searchParams.get("view") || "tesouraria";

  useEffect(() => {
    localStorage.setItem("dashboard-show-expenses", String(showExpenses));
  }, [showExpenses]);

  // Fetch Transactions and Categories
  const { data: txs, isLoading: txsLoading, error: txsError } = useQuery({
    queryKey: ["dashboard-transactions", organization?.id, year, month],
    queryFn: async () => {
      if (!organization?.id) return [];
      let query = supabase
        .from("transactions")
        .select(`*, categories!category_id(name)`)
        .eq("organization_id", organization.id)
        .gte("date", `${year}-01-01`)
        .lte("date", `${year}-12-31`);

      if (month !== "all") {
        const lastDay = new Date(parseInt(year), parseInt(month), 0).getDate();
        query = query.gte("date", `${year}-${month}-01`).lte("date", `${year}-${month}-${lastDay.toString().padStart(2, '0')}`);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data || [];
    },
    enabled: !!organization?.id && canManageFinances,
    staleTime: 1000 * 60 * 2, // 2 minutes
  });

  // Fetch Secretariat Counts
  const { data: counts, isLoading: countsLoading } = useQuery({
    queryKey: ["dashboard-counts", organization?.id],
    queryFn: async () => {
      if (!organization?.id) return { memberCount: 0, deptCount: 0, eventCount: 0 };
      const [
        { count: mCount },
        { count: dCount },
        { count: eCount }
      ] = await Promise.all([
        supabase.from("members").select("*", { count: "exact", head: true }).eq("organization_id", organization.id).eq("status", "active"),
        supabase.from("departments").select("*", { count: "exact", head: true }).eq("organization_id", organization.id),
        supabase.from("events").select("*", { count: "exact", head: true }).eq("organization_id", organization.id),
      ]);
      return {
        memberCount: mCount || 0,
        deptCount: dCount || 0,
        eventCount: eCount || 0
      };
    },
    enabled: !!organization?.id,
    staleTime: 1000 * 60 * 5,
  });

  useEffect(() => {
    if (txsError) toast.error("Erro ao carregar dados do financeiro");
  }, [txsError]);

  // Combined Data Processing
  const { stats, chartData } = useMemo(() => {
    const newStats = {
      entradas: 0,
      saidas: 0,
      pendenteSaida: 0,
      dizimos: 0,
      ofertas: 0,
      count: txs?.length || 0,
      memberCount: counts?.memberCount || 0,
      deptCount: counts?.deptCount || 0,
      eventCount: counts?.eventCount || 0
    };

    const monthlyAggr: Record<string, any> = {};
    monthNames.forEach(m => {
      monthlyAggr[m] = { month: m, entradas: 0, saidas: 0, dizimos: 0, ofertas: 0 };
    });

    txs?.forEach(tx => {
      const amt = tx.amount || 0;
      const inc = tx.type === "income";
      const cat = tx.categories?.name?.toLowerCase() || "";
      const tDate = new Date(tx.date);
      const mN = monthNames[tDate.getMonth()];

      // Se for sa├¡da e estiver pendente, somamos apenas ao total de sa├¡das e pendentes
      if (tx.status === 'pending') {
        if (!inc) {
          newStats.pendenteSaida += amt;
          monthlyAggr[mN].saidas += amt;
        }
        return;
      }

      if (inc) {
        newStats.entradas += amt;
        monthlyAggr[mN].entradas += amt;
        if (cat.includes("d├¡zimo")) {
          newStats.dizimos += amt;
          monthlyAggr[mN].dizimos += amt;
        } else if (cat.includes("oferta")) {
          newStats.ofertas += amt;
          monthlyAggr[mN].ofertas += amt;
        }
      } else {
        newStats.saidas += amt;
        monthlyAggr[mN].saidas += amt;
      }
    });

    return {
      stats: newStats,
      chartData: Object.values(monthlyAggr)
    };
  }, [txs, counts]);

  const saldoCaixa = stats.entradas - stats.saidas;
  const saldoProjetado = stats.entradas - (stats.saidas + stats.pendenteSaida);
  const loading = txsLoading || countsLoading;

  const summaryCards = useMemo(() => [
    { title: "Total Entradas", value: stats.entradas, prefix: "R$ ", suffix: "", decimals: 2, icon: TrendingUp, positive: true, muted: true },
    { title: "Total Sa├¡das", value: stats.saidas + stats.pendenteSaida, prefix: "R$ ", suffix: "", decimals: 2, icon: TrendingDown, positive: false, muted: true },
    { title: "Saldo em Caixa", value: saldoCaixa, prefix: "R$ ", suffix: "", decimals: 2, icon: Wallet, positive: saldoCaixa >= 0, primary: true },
    { title: "Saldo Projetado", value: saldoProjetado, prefix: "R$ ", suffix: "", decimals: 2, icon: Layers, positive: saldoProjetado >= 0, muted: true },
    { title: "Contas a Pagar", value: stats.pendenteSaida, prefix: "R$ ", suffix: "", decimals: 2, icon: AlertCircle, positive: false, color: "text-orange-600", link: "/lancamentos?status=pending" },
  ], [stats, saldoCaixa, saldoProjetado]);

  const periodLabel = month === "all"
    ? `Jan ${year} ÔÇö Dez ${year}`
    : `${monthNames[parseInt(month) - 1]} ${year}`;

  const visibleCards = useMemo(() => {
    if (canManageFinances) return summaryCards;
    return []; // No Treasury cards for non-treasury users
  }, [canManageFinances, summaryCards]);

  const refreshData = () => {
    queryClient.invalidateQueries({ queryKey: ["dashboard-transactions"] });
    queryClient.invalidateQueries({ queryKey: ["dashboard-counts"] });
  };

  if (!organization) return null;

  return (
    <>
      <div className="animate-fade-in space-y-10 pb-10">
        <div className="flex items-center justify-between flex-wrap gap-6 bg-secondary/5 p-4 rounded-[1.5rem] border border-border/40">
          <div>
            <h1 className="text-2xl font-bold text-foreground tracking-tight">Painel de Gest├úo</h1>
            <p className="text-[11px] font-medium text-muted-foreground uppercase tracking-widest mt-1 opacity-70">{organization.name} ÔÇö {periodLabel}</p>
          </div>
          <div className="flex items-center gap-3">
            {canManageFinances && (
              <div className="flex items-center gap-2 mr-2">
                <QuickEntryDialog onSuccess={refreshData} />
                <TransactionsDialog
                  onSuccess={refreshData}
                  trigger={
                    <Button className="h-10 px-6 text-xs font-bold gap-2 premium-button bg-primary text-primary-foreground">
                      <Plus className="h-4.5 w-4.5" />
                      Novo Lan├ºamento
                    </Button>
                  }
                />
              </div>
            )}
            <div className="h-8 w-[1px] bg-border/40 mx-1 hidden sm:block" />
            <Select value={year} onValueChange={setYear}>
              <SelectTrigger className="h-10 w-24 text-xs bg-background border-border/40 rounded-xl"><SelectValue /></SelectTrigger>
              <SelectContent>
                <SelectItem value="2026">2026</SelectItem>
                <SelectItem value="2025">2025</SelectItem>
                <SelectItem value="2024">2024</SelectItem>
              </SelectContent>
            </Select>
            <Select value={month} onValueChange={setMonth}>
              <SelectTrigger className="h-10 w-40 text-xs bg-background border-border/40 rounded-xl"><SelectValue /></SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todo o ano</SelectItem>
                {monthNames.map((m, i) => (
                  <SelectItem key={i} value={String(i + 1).padStart(2, "0")}>{m}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </div>

        <AIInsightCard mode={activeTab as "tesouraria" | "secretaria"} />

        {activeTab === "tesouraria" ? (
          <div className="space-y-8 animate-in fade-in duration-700">
            <div className={`grid gap-5 ${canManageFinances ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-5' : 'grid-cols-1 md:grid-cols-3'}`}>
              {visibleCards.map((card) => (
                <Card key={card.title} className={cn(
                  "stat-card border-none hover:ring-2 ring-primary/5",
                  card.primary ? 'ring-2 ring-primary/40 bg-gradient-to-br from-card to-primary/5' : ''
                )}>
                  <CardContent className="p-5">
                    <div className="flex items-center justify-between mb-4">
                      <div className="h-10 w-10 rounded-xl bg-secondary/50 flex items-center justify-center border border-border/40">
                        <card.icon className={cn(
                          "h-5 w-5",
                          card.primary ? 'text-primary' : 'text-muted-foreground/60'
                        )} />
                      </div>
                      {card.link && (
                        <Link to={card.link} className="text-[10px] text-primary font-bold uppercase tracking-widest hover:underline">Ver todos</Link>
                      )}
                    </div>
                    <div className="space-y-1">
                      <span className={cn(
                        "text-[10px] font-black uppercase tracking-widest block",
                        card.primary ? 'text-foreground' : 'text-muted-foreground/80'
                      )}>{card.title}</span>
                      <div className="flex items-baseline gap-1">
                        {loading ? (
                          <Skeleton className="h-8 w-24" />
                        ) : (
                          <span className="text-2xl font-black font-mono tabular-nums tracking-tight">
                            <Counter
                              value={card.value}
                              prefix={card.prefix}
                              suffix={card.suffix}
                              decimals={card.decimals}
                            />
                          </span>
                        )}
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>

            <div className={`grid gap-6 grid-cols-1 ${canManageFinances ? 'lg:grid-cols-[1fr_320px]' : ''}`}>
              {canManageFinances && (
                <Card className="stat-card border-none overflow-hidden">
                  <CardHeader className="bg-secondary/10 border-b border-border/40 py-5 flex flex-row items-center justify-between">
                    <div>
                      <CardTitle className="text-base font-bold">Fluxo de Caixa Mensal</CardTitle>
                      <p className="text-[11px] font-medium text-muted-foreground uppercase tracking-widest mt-0.5">Entradas vs Sa├¡das</p>
                    </div>
                  </CardHeader>
                  <CardContent className="pt-8 px-6 pb-6">
                    <div className="h-[280px]">
                      {loading ? (
                        <div className="h-full flex items-end gap-2 px-2 pb-4">
                          {Array.from({ length: 12 }).map((_, i) => (
                            <Skeleton key={i} className="w-full" style={{ height: `${Math.random() * 60 + 20}%` }} />
                          ))}
                        </div>
                      ) : (
                        <ResponsiveContainer width="100%" height="100%">
                          <BarChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }} barGap={6}>
                            <CartesianGrid strokeDasharray="4 4" stroke="hsla(var(--border), 0.5)" vertical={false} />
                            <XAxis dataKey="month" tick={{ fontSize: 10, fontWeight: 700, fill: "hsl(var(--muted-foreground))" }} axisLine={false} tickLine={false} height={30} />
                            <YAxis tick={{ fontSize: 10, fontWeight: 700, fill: "hsl(var(--muted-foreground))" }} axisLine={false} tickLine={false} tickFormatter={formatYAxis} />
                            <Tooltip
                              cursor={{ fill: 'hsl(var(--secondary))', opacity: 0.4 }}
                              contentStyle={{ background: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: 16, fontSize: 12, boxShadow: '0 10px 25px -10px rgba(0,0,0,0.1)' }}
                              formatter={(v: number) => [`R$ ${v.toLocaleString("pt-BR")}`, ""]}
                            />
                            <Bar dataKey="entradas" fill="hsl(var(--chart-blue))" radius={[6, 6, 0, 0]} barSize={32} />
                            <Bar dataKey="saidas" fill="hsl(var(--chart-pink))" radius={[6, 6, 0, 0]} barSize={32} />
                          </BarChart>
                        </ResponsiveContainer>
                      )}
                    </div>
                  </CardContent>
                </Card>
              )}

              <Card className="stat-card border-none overflow-hidden h-fit">
                <CardHeader className="bg-secondary/10 border-b border-border/40 py-4 flex flex-row items-center justify-between space-y-0 text-center">
                  <CardTitle className="text-[11px] font-black uppercase tracking-[0.2em] w-full">Resumo Mensal</CardTitle>
                </CardHeader>
                <CardContent className="p-6">
                  <div className="space-y-4">
                    {canManageFinances && (
                      <div className="space-y-4">
                        <div className="flex items-center justify-between p-3 rounded-xl bg-secondary/20 border border-border/40">
                          <span className="text-[10px] font-bold text-muted-foreground uppercase">Ver Despesas</span>
                          <Switch
                            checked={showExpenses}
                            onCheckedChange={setShowExpenses}
                            className="scale-75 data-[state=checked]:bg-destructive"
                          />
                        </div>

                        <div className="space-y-3 pt-2">
                          {showExpenses && (
                            <div className="flex justify-between items-center pb-2 border-b border-border/40 animate-in slide-in-from-top-2 duration-300">
                              <span className="text-[11px] font-medium text-muted-foreground">Total Sa├¡das</span>
                              <span className="text-sm font-bold font-mono text-destructive">
                                {loading ? <Skeleton className="h-4 w-24" /> : `- R$ ${stats.saidas.toLocaleString("pt-BR")}`}
                              </span>
                            </div>
                          )}
                          <div className="flex justify-between items-center pb-2 border-b border-border/40">
                            <span className="text-[11px] font-medium text-muted-foreground">D├¡zimos</span>
                            <span className="text-sm font-bold font-mono text-emerald-500">
                              {loading ? <Skeleton className="h-4 w-24" /> : `R$ ${stats.dizimos.toLocaleString("pt-BR")}`}
                            </span>
                          </div>
                          <div className="flex justify-between items-center pb-2 border-b border-border/40">
                            <span className="text-[11px] font-medium text-muted-foreground">Ofertas</span>
                            <span className="text-sm font-bold font-mono text-emerald-500">
                              {loading ? <Skeleton className="h-4 w-24" /> : `R$ ${stats.ofertas.toLocaleString("pt-BR")}`}
                            </span>
                          </div>
                          <div className="flex justify-between items-center pt-3 p-4 bg-primary/5 rounded-2xl border border-primary/10">
                            <span className="text-[11px] font-black uppercase text-foreground">Saldo L├¡quido</span>
                            {loading ? (
                              <Skeleton className="h-6 w-28" />
                            ) : (
                              <span className={cn(
                                "text-lg font-black font-mono tracking-tight",
                                saldoCaixa >= 0 ? "text-primary" : "text-destructive"
                              )}>
                                {`R$ ${saldoCaixa.toLocaleString("pt-BR")}`}
                              </span>
                            )}
                          </div>
                        </div>
                      </div>
                    )}

                    <div className={cn(
                      "mt-6 pt-6 border-t border-border/40 space-y-4",
                      !canManageFinances ? 'mt-0 pt-0 border-t-0' : ''
                    )}>
                      <h4 className="text-[10px] font-black uppercase tracking-[0.25em] text-muted-foreground/60">Controle Interno</h4>
                      <div className="grid grid-cols-2 gap-3">
                        <div className="p-4 rounded-2xl bg-secondary/30 border border-border/20 group hover:border-primary/20 transition-all">
                          <Layers className="h-4 w-4 text-primary/60 mb-2 transition-transform group-hover:scale-110" />
                          <div className="space-y-0.5">
                            <span className="text-[9px] font-bold text-muted-foreground uppercase">Deptos</span>
                            <p className="text-sm font-black tabular-nums">{loading ? "..." : stats.deptCount}</p>
                          </div>
                        </div>
                        <div className="p-4 rounded-2xl bg-secondary/30 border border-border/20 group hover:border-primary/20 transition-all">
                          <CalendarDays className="h-4 w-4 text-primary/60 mb-2 transition-transform group-hover:scale-110" />
                          <div className="space-y-0.5">
                            <span className="text-[9px] font-bold text-muted-foreground uppercase">Eventos</span>
                            <p className="text-sm font-black tabular-nums">{loading ? "..." : stats.eventCount}</p>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                  <Link to="/lancamentos?tab=relatorios" className="block w-full mt-6">
                    <Button variant="outline" className="w-full h-10 text-[10px] font-bold uppercase tracking-widest border-border/60 premium-button hover:bg-primary/5 hover:text-primary transition-all">
                      <Eye className="h-4 w-4 mr-2" />
                      Visualizar Relat├│rio
                    </Button>
                  </Link>
                </CardContent>
              </Card>
            </div>

            {canManageFinances && (
              <Card className="stat-card border-none overflow-hidden">
                <CardHeader className="bg-secondary/10 border-b border-border/40 py-4">
                  <CardTitle className="text-sm font-bold flex items-center gap-2">
                    <TrendingUp className="h-4 w-4 text-primary" /> Tend├¬ncia: D├¡zimos & Ofertas
                  </CardTitle>
                </CardHeader>
                <CardContent className="pt-8 px-6 pb-6">
                  <div className="h-[220px]">
                    {loading ? (
                      <Skeleton className="h-full w-full rounded-2xl opacity-20" />
                    ) : (
                      <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 5 }}>
                          <CartesianGrid strokeDasharray="4 4" stroke="hsla(var(--border), 0.5)" vertical={false} />
                          <XAxis dataKey="month" tick={{ fontSize: 10, fontWeight: 700, fill: "hsl(var(--muted-foreground))" }} axisLine={false} tickLine={false} height={25} />
                          <YAxis tick={{ fontSize: 10, fontWeight: 700, fill: "hsl(var(--muted-foreground))" }} axisLine={false} tickLine={false} tickFormatter={formatYAxis} />
                          <Tooltip
                            contentStyle={{ background: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: 16, fontSize: 11, boxShadow: '0 10px 25px -10px rgba(0,0,0,0.1)' }}
                          />
                          <defs>
                            <linearGradient id="gradAreaBlue" x1="0" y1="0" x2="0" y2="1">
                              <stop offset="0%" stopColor="hsl(var(--chart-blue))" stopOpacity={0.25} />
                              <stop offset="100%" stopColor="hsl(var(--chart-blue))" stopOpacity={0} />
                            </linearGradient>
                          </defs>
                          <Area type="monotone" dataKey="dizimos" name="D├¡zimos" stroke="hsl(var(--chart-blue))" strokeWidth={3} fill="url(#gradAreaBlue)" dot={{ r: 4, fill: 'hsl(var(--chart-blue))', strokeWidth: 2, stroke: 'hsl(var(--card))' }} activeDot={{ r: 6, strokeWidth: 0 }} />
                          <Area type="monotone" dataKey="ofertas" name="Ofertas" stroke="hsl(var(--chart-pink))" strokeWidth={2} fill="none" dot={false} strokeDasharray="6 6" />
                        </AreaChart>
                      </ResponsiveContainer>
                    )}
                  </div>
                </CardContent>
              </Card>
            )}
          </div>
        ) : (
          <div className="animate-in fade-in zoom-in-95 duration-700">
            <SecretariaDashboard />
          </div>
        )}
      </div>
    </>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Users, Plus, Music, Trash2, Pencil, Loader2, Search, X } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import { toast } from "sonner";
import { supabase } from "@/lib/supabase";
import { useChurch } from "@/contexts/ChurchContext";
import { PermissionGuard } from "@/components/PermissionGuard";
import type { Database } from "@/types/database.types";

type Department = Database["public"]["Tables"]["departments"]["Row"];

const colorOptions = [
  { value: "bg-chart-pink/15 text-chart-pink", label: "Rosa" },
  { value: "bg-chart-blue/15 text-chart-blue", label: "Azul" },
  { value: "bg-primary/15 text-primary", label: "├émbar" },
  { value: "bg-success/15 text-success", label: "Verde" },
];

const emptyDep = { name: "", leader_name: "", member_count: "", color: colorOptions[0].value };

export default function Departamentos() {
  const { organization, profile, isAdmin, canManageSecretariat } = useChurch();
  const [items, setItems] = useState<Department[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState(emptyDep);
  const [subGroupDialog, setSubGroupDialog] = useState<string | null>(null);
  const [newSubGroup, setNewSubGroup] = useState({ name: "", role: "" });

  useEffect(() => {
    if (organization?.id) fetchDepartments();
  }, [organization?.id]);

  const fetchDepartments = async () => {
    try {
      setLoading(true);
      let query = supabase
        .from("departments")
        .select("*")
        .eq("organization_id", organization!.id);

      if (profile?.role === 'leader' && profile.department_id) {
        query = query.eq("id", profile.department_id);
      }

      const { data, error } = await query.order("name");
      if (error) throw error;
      setItems(data || []);
    } catch (err) {
      toast.error("Erro ao carregar departamentos");
    } finally {
      setLoading(false);
    }
  };

  const openCreate = () => { setEditingId(null); setForm(emptyDep); setDialogOpen(true); };
  const openEdit = (d: Department) => {
    setEditingId(d.id);
    setForm({
      name: d.name,
      leader_name: d.leader_name || "",
      member_count: String(d.member_count || 0),
      color: d.color || colorOptions[0].value
    });
    setDialogOpen(true);
  };

  const handleSave = async () => {
    if (!form.name || !organization?.id) return;
    setIsSaving(true);
    try {
      const payload = {
        name: form.name,
        leader_name: form.leader_name,
        member_count: parseInt(form.member_count) || 0,
        color: form.color,
        organization_id: organization.id,
      };

      if (editingId) {
        const { error } = await supabase.from("departments").update(payload).eq("id", editingId);
        if (error) throw error;
      } else {
        const { error } = await supabase.from("departments").insert([payload]);
        if (error) throw error;
      }
      setDialogOpen(false);
      fetchDepartments();
      toast.success(editingId ? "Departamento atualizado" : "Departamento criado");
    } catch (err) {
      console.error("Error saving department:", err);
      toast.error("Erro ao salvar departamento");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Deseja realmente remover este departamento?")) return;
    try {
      const { error } = await supabase.from("departments").delete().eq("id", id);
      if (error) throw error;
      toast.success("Departamento removido");
      setItems(prev => prev.filter(d => d.id !== id));
    } catch (err) {
      toast.error("Erro ao remover departamento");
    }
  };

  const handleAddSubGroup = async (dep: Department) => {
    if (!newSubGroup.name) return;
    const currentSubGroups = Array.isArray(dep.subgroups) ? dep.subgroups : [];
    const updated = [...currentSubGroups, { id: Date.now(), name: newSubGroup.name, role: newSubGroup.role }];

    try {
      const { error } = await supabase.from("departments").update({ subgroups: updated }).eq("id", dep.id);
      if (error) throw error;
      setNewSubGroup({ name: "", role: "" });
      setSubGroupDialog(null);
      fetchDepartments();
      toast.success("Sub-grupo adicionado");
    } catch (err) { toast.error("Erro ao adicionar sub-grupo"); }
  };

  const handleDeleteSubGroup = async (dep: Department, sgId: number) => {
    const currentSubGroups = Array.isArray(dep.subgroups) ? dep.subgroups : [];
    const updated = currentSubGroups.filter((sg: any) => sg.id !== sgId);
    try {
      const { error } = await supabase.from("departments").update({ subgroups: updated }).eq("id", dep.id);
      if (error) throw error;
      fetchDepartments();
      toast.success("Sub-grupo removido");
    } catch (err) { toast.error("Erro ao remover sub-grupo"); }
  };

  if (!organization) return <div className="p-8 text-center text-muted-foreground font-mono">Carregando...</div>;

  return (
    <div className="animate-fade-in space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-semibold text-foreground">Departamentos</h2>
          <p className="text-muted-foreground text-[12px] mt-1">Gest├úo de minist├®rios ÔÇö {organization.name}</p>
        </div>
        <PermissionGuard requireSecretariat>
          <Button className="bg-primary text-primary-foreground hover:bg-primary/90 h-9 text-xs rounded-full px-6" onClick={openCreate}>
            <Plus className="h-4 w-4 mr-2" />Novo departamento
          </Button>
        </PermissionGuard>
      </div>

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="bg-card border-border">
          <DialogHeader><DialogTitle>{editingId ? "Editar Departamento" : "Novo Departamento"}</DialogTitle></DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="space-y-2"><Label className="text-[13px]">Nome *</Label><Input placeholder="Ex: Mulheres" value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} /></div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2"><Label className="text-[13px]">L├¡der</Label><Input placeholder="Nome do l├¡der" value={form.leader_name} onChange={(e) => setForm({ ...form, leader_name: e.target.value })} /></div>
              <div className="space-y-2"><Label className="text-[13px]">Membros</Label><Input type="number" placeholder="0" value={form.member_count} onChange={(e) => setForm({ ...form, member_count: e.target.value })} /></div>
            </div>
            <div className="space-y-2">
              <Label className="text-[13px]">Cor de Destaque</Label>
              <Select value={form.color} onValueChange={(v) => setForm({ ...form, color: v })}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>{colorOptions.map((c) => <SelectItem key={c.label} value={c.value}>{c.label}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div className="flex justify-center pt-2">
              <Button className="w-full sm:w-[140px] rounded-full" onClick={handleSave} disabled={isSaving}>
                {isSaving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                {editingId ? "Atualizar" : "Salvar"}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <Card className="bg-card border-border shadow-sm overflow-hidden">
        <CardHeader className="pb-3 bg-secondary/10">
          <div className="flex flex-col gap-3">
            <div className="flex items-center gap-4">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input placeholder="Buscar departamentos..." className="pl-9 h-9 text-xs" />
              </div>
            </div>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          <ScrollArea className="h-[calc(100vh-340px)] w-full">
            <Table className="border-collapse border border-border/50">
              <TableHeader className="sticky top-0 bg-secondary/20 backdrop-blur-sm z-10 border-b border-border">
                <TableRow className="hover:bg-transparent">
                  <TableHead className="text-[11px] font-black text-muted-foreground text-center border-r border-border/50 pl-6">Nome</TableHead>
                  <TableHead className="text-[11px] font-black text-muted-foreground text-center border-r border-border/50">L├¡der Principal</TableHead>
                  <TableHead className="text-[11px] font-black text-muted-foreground text-center border-r border-border/50">Membros</TableHead>
                  <TableHead className="text-[11px] font-black text-muted-foreground text-center border-r border-border/50">Sub-grupos</TableHead>
                  <TableHead className="w-[6%] text-[11px] font-black text-muted-foreground text-center">A├º├Áes</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                  Array.from({ length: 5 }).map((_, i) => (
                    <TableRow key={i}>
                      <TableCell className="pl-6 border-r border-border/50"><Skeleton className="h-6 w-full" /></TableCell>
                      <TableCell className="border-r border-border/50"><Skeleton className="h-6 w-full" /></TableCell>
                      <TableCell className="border-r border-border/50"><Skeleton className="h-4 w-full" /></TableCell>
                      <TableCell className="border-r border-border/50"><Skeleton className="h-4 w-full" /></TableCell>
                      <TableCell><Skeleton className="h-8 w-8 rounded-lg" /></TableCell>
                    </TableRow>
                  ))
                ) : (
                  <>
                    {items.map((dep) => (
                      <TableRow
                        key={dep.id}
                        className="group transition-colors odd:bg-transparent even:bg-secondary/10 hover:bg-secondary/20 border-b border-border/50"
                      >
                        <TableCell className="pl-6 py-2 border-r border-border/50 text-center">
                          <Badge variant="outline" className={`${dep.color || colorOptions[0].value} border-border/50 text-[12px] font-bold h-6 px-3`}>
                            {dep.name}
                          </Badge>
                        </TableCell>
                        <TableCell className="text-center border-r border-border/50 py-2 font-medium text-[14px]">
                          {dep.leader_name || "N├âO INFORMADO"}
                        </TableCell>
                        <TableCell className="text-center border-r border-border/50 py-2 font-mono text-[13px] font-bold text-primary">
                          {dep.member_count || 0}
                        </TableCell>
                        <TableCell className="text-center border-r border-border/50 py-2">
                          <div className="flex flex-wrap gap-1 justify-center">
                            {Array.isArray(dep.subgroups) && dep.subgroups.length > 0 ? (
                              dep.subgroups.map((sg: any) => (
                                <Badge key={sg.id} variant="secondary" className="text-[9px] h-4 px-1.5 bg-secondary/30 border-0 flex items-center gap-1 group/sg">
                                  {sg.name}
                                  <button onClick={(e) => { e.stopPropagation(); handleDeleteSubGroup(dep, sg.id); }} className="hover:text-destructive"><X className="h-2 w-2" /></button>
                                </Badge>
                              ))
                            ) : (
                              <span className="text-[10px] text-muted-foreground italic">Nenhum</span>
                            )}
