    try {
      const monthsToFetch = period === "3_months" ? 3 : period === "6_months" ? 6 : 12;
      const startDate = new Date();
      startDate.setMonth(startDate.getMonth() - (monthsToFetch - 1));
      startDate.setDate(1);

      let query = supabase
        .from("members")
        .select("created_at, congregation_id")
