        data?.forEach(m => {
          const cName = congregations.find(c => c.id === m.congregation_id)?.name || "Sede";
          if (comp[cName]) comp[cName].count++;
        });
        setCongregationGrowthData(Object.values(comp).filter(c => c.count > 0));
      } else {
        setCongregationGrowthData([]);
