import { useState, useEffect } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Plus, Loader2, Heart, Users, ClipboardCheck } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";
import { supabase } from "@/lib/supabase";
import { useChurch } from "@/contexts/ChurchContext";
import { Skeleton } from "@/components/ui/skeleton";
import type { Database } from "@/types/database.types";

type Family = { id: string; name: string; address?: string; members_count?: number; needs?: string };
type Assistance = { id: string; family_id?: string; assistance_type: string; delivery_date: string; items_count: number; status: string; families?: Family };

export default function ServicoSocial() {
  const { organization } = useChurch();
  const [families, setFamilies] = useState<Family[]>([]);
  const [assistances, setAssistances] = useState<Assistance[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  const [dialogOpen, setDialogOpen] = useState(false);
  const [mode, setMode] = useState<"family" | "assistance">("family");
  const [form, setForm] = useState({ name: "", address: "", members_count: "1", needs: "", family_id: "", assistance_type: "Cesta B├ísica", items_count: "1", status: "delivered" });

  useEffect(() => {
    if (organization?.id) fetchData();
  }, [organization?.id]);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [{ data: fams }, { data: assts }] = await Promise.all([
        supabase.from("families").select("*").eq("organization_id", organization!.id).order("name"),
        supabase.from("social_assistance").select("*, families(name)").eq("organization_id", organization!.id).order("delivery_date", { ascending: false })
      ]);
      setFamilies(fams || []);
      setAssistances((assts as any) || []);
    } catch (err) {
      toast.error("Erro ao carregar dados sociais");
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async () => {
    if (!organization?.id) return;
    setIsSaving(true);
    try {
      if (mode === "family") {
        if (!form.name) return;
        const { error } = await supabase.from("families").insert([{ name: form.name, address: form.address, members_count: parseInt(form.members_count), needs: form.needs, organization_id: organization.id }]);
        if (error) throw error;
        toast.success("Fam├¡lia registrada");
      } else {
        if (!form.family_id) return;
        const { error } = await supabase.from("social_assistance").insert([{ family_id: form.family_id, assistance_type: form.assistance_type, items_count: parseInt(form.items_count), status: form.status, organization_id: organization.id }]);
        if (error) throw error;
        toast.success("Entrega registrada");
      }
      setDialogOpen(false);
      fetchData();
    } catch (err) {
      toast.error("Erro ao salvar registro");
    } finally {
      setIsSaving(false);
    }
  };

  if (!organization) return null;

  return (
    <div className="animate-fade-in space-y-6">
      <div className="flex items-center justify-end">
        <div className="flex gap-2">
          <Button size="sm" variant="outline" className="h-9 text-xs rounded-full px-5" onClick={() => { setMode("family"); setDialogOpen(true); }}><Plus className="h-4 w-4 mr-2" />Fam├¡lia</Button>
          <Button size="sm" className="h-9 text-xs rounded-full px-5" onClick={() => { setMode("assistance"); setDialogOpen(true); }}><Plus className="h-4 w-4 mr-2" />Registrar Aux├¡lio</Button>
        </div>
      </div>

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="bg-card border-border border-primary/20 shadow-2xl">
          <DialogHeader><DialogTitle className="flex items-center gap-2"><Heart className="h-5 w-5 text-primary" /> {mode === "family" ? "Mapear Fam├¡lia" : "Registrar Aux├¡lio"}</DialogTitle></DialogHeader>
          <div className="grid gap-4 py-4">
            {mode === "family" ? (
              <>
                <div className="space-y-2"><Label className="text-[13px]">Nome da Fam├¡lia / Respons├ível *</Label><Input value={form.name} className="h-10" onChange={e => setForm({ ...form, name: e.target.value })} /></div>
                <div className="space-y-2"><Label className="text-[13px]">Endere├ºo</Label><Input value={form.address} className="h-10" onChange={e => setForm({ ...form, address: e.target.value })} /></div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2"><Label className="text-[13px]">Qtd. Membros</Label><Input type="number" value={form.members_count} className="h-10" onChange={e => setForm({ ...form, members_count: e.target.value })} /></div>
                  <div className="space-y-2"><Label className="text-[13px]">Principais Necessidades</Label><Input placeholder="Ex: Alimentos, Rem├®dios" className="h-10" value={form.needs} onChange={e => setForm({ ...form, needs: e.target.value })} /></div>
                </div>
              </>
            ) : (
              <>
                <div className="space-y-2">
                  <Label className="text-[13px]">Selecionar Fam├¡lia *</Label>
                  <Select value={form.family_id} onValueChange={v => setForm({ ...form, family_id: v })}>
                    <SelectTrigger className="h-10"><SelectValue placeholder="Selecione a fam├¡lia beneficiada" /></SelectTrigger>
                    <SelectContent>{families.map(f => <SelectItem key={f.id} value={f.id}>{f.name}</SelectItem>)}</SelectContent>
                  </Select>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2"><Label className="text-[13px]">Qtd. Itens Entregues</Label><Input type="number" value={form.items_count} className="h-10" onChange={e => setForm({ ...form, items_count: e.target.value })} /></div>
                  <div className="space-y-2">
                    <Label className="text-[13px]">Status da Entrega</Label>
                    <Select value={form.status} onValueChange={v => setForm({ ...form, status: v })}>
                      <SelectTrigger className="h-10"><SelectValue /></SelectTrigger>
                      <SelectContent><SelectItem value="delivered">Entregue</SelectItem><SelectItem value="pending">Pendente</SelectItem></SelectContent>
                    </Select>
                  </div>
                </div>
              </>
            )}
            <Button className="w-full h-11 text-sm font-bold shadow-lg shadow-primary/10 mt-2 rounded-full" onClick={handleSave} disabled={isSaving}>
              {isSaving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />} {mode === "family" ? "Salvar Cadastro" : "Confirmar Entrega"}
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      <Tabs defaultValue="asst" className="w-full">
        <TabsList className="bg-secondary/30 p-1 border border-border/50 h-10 mb-4 inline-flex">
          <TabsTrigger value="asst" className="text-xs px-4 data-[state=active]:bg-background data-[state=active]:shadow-sm"><ClipboardCheck className="h-3.5 w-3.5 mr-2" /> Registro de Aux├¡lios</TabsTrigger>
          <TabsTrigger value="fam" className="text-xs px-4 data-[state=active]:bg-background data-[state=active]:shadow-sm"><Users className="h-3.5 w-3.5 mr-2" /> Fam├¡lias Mapeadas</TabsTrigger>
        </TabsList>

        <TabsContent value="asst" className="mt-0 focus-visible:ring-0">
          <Card className="border-border shadow-sm overflow-hidden border-primary/5">
            <ScrollArea className="h-[calc(100vh-450px)] w-full">
              <Table className="border-collapse border border-border/50">
                <TableHeader className="sticky top-0 bg-secondary/20 backdrop-blur-sm z-10 border-b border-border">
                  <TableRow className="hover:bg-transparent">
                    <TableHead className="text-[11px] font-black text-muted-foreground border-r border-border/50 px-4 text-center pl-6">Fam├¡lia Beneficiada</TableHead>
                    <TableHead className="text-[11px] font-black text-muted-foreground border-r border-border/50 px-4 text-center">Data</TableHead>
                    <TableHead className="text-[11px] font-black text-muted-foreground border-r border-border/50 px-4 text-center">Volume</TableHead>
                    <TableHead className="text-[11px] font-black text-muted-foreground px-4 text-center pr-6">Status</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {loading ? (
                    Array.from({ length: 5 }).map((_, i) => (
                      <TableRow key={i}><TableCell colSpan={4} className="py-2"><Skeleton className="h-6 w-full" /></TableCell></TableRow>
                    ))
                  ) : (
                    <>
                      {assistances.map(a => (
                        <TableRow key={a.id} className="group transition-colors odd:bg-transparent even:bg-secondary/10 hover:bg-secondary/20 border-b border-border/50">
                          <TableCell className="pl-6 py-2 border-r border-border/50 text-center">
                            <div className="flex items-center gap-3 justify-center text-center">
                              <div className="h-8 w-8 rounded-lg bg-primary/10 flex items-center justify-center border border-primary/20 shrink-0">
                                <Heart className="h-4 w-4 text-primary" />
                              </div>
                              <div className="text-center">
                                <p className="text-[13px] font-bold text-foreground leading-tight">{a.families?.name || "Desconhecido"}</p>
                                <p className="text-[11px] text-muted-foreground mt-0.5">{a.assistance_type}</p>
                              </div>
                            </div>
                          </TableCell>
                          <TableCell className="text-center text-[12px] font-mono font-medium text-muted-foreground border-r border-border/50 py-2">
                            {new Date(a.delivery_date + 'T12:00:00').toLocaleDateString("pt-BR")}
                          </TableCell>
                          <TableCell className="text-center border-r border-border/50 py-2">
                            <Badge variant="outline" className="bg-secondary/20 text-foreground font-black text-[10px] h-5 border-border/50">
                              {a.items_count} ITENS
                            </Badge>
                          </TableCell>
                          <TableCell className="text-center pr-6 py-2">
                            <Badge variant="outline" className={`text-[10px] font-black px-2 py-0 h-5 border-border/50 rounded-full ${a.status === "delivered" ? "bg-success/15 text-success" : "bg-primary/15 text-primary"}`}>
                              {a.status === "delivered" ? "ENTREGUE" : "PENDENTE"}
                            </Badge>
                          </TableCell>
                        </TableRow>
                      ))}
                      {!loading && assistances.length === 0 && (
                        <TableRow><TableCell colSpan={4} className="text-center py-20 text-muted-foreground italic border-b border-border/50">Nenhum aux├¡lio registrado ainda</TableCell></TableRow>
                      )}
                    </>
                  )}
                </TableBody>
              </Table>
            </ScrollArea>
          </Card>
        </TabsContent>

        <TabsContent value="fam" className="mt-0 focus-visible:ring-0">
          <Card className="border-border shadow-sm overflow-hidden border-primary/5">
            <ScrollArea className="h-[calc(100vh-450px)] w-full">
              <Table className="border-collapse border border-border/50">
                <TableHeader className="sticky top-0 bg-secondary/20 backdrop-blur-sm z-10 border-b border-border">
                  <TableRow className="hover:bg-transparent">
                    <TableHead className="text-[11px] font-black text-muted-foreground border-r border-border/50 px-4 text-center pl-6">Fam├¡lia / Respons├ível</TableHead>
                    <TableHead className="text-[11px] font-black text-muted-foreground border-r border-border/50 px-4 text-center">Endere├ºo</TableHead>
