                          </TableCell>
                        </TableRow>
                      ))}
                      {!loading && families.length === 0 && (
                        <TableRow><TableCell colSpan={4} className="text-center py-20 text-muted-foreground italic border-b border-border/50">Nenhuma fam├¡lia mapeada</TableCell></TableRow>
                      )}
                    </>
                  )}
                </TableBody>
              </Table>
            </ScrollArea>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
